var incenseData = [{"id":"平齐式-1","name":"振拔香","category":"平齐式","style_description":"左炷香灰左弯,其余直立。","meaning_poem":"振拔香号主振兴,\n艰辛自力脱困境。\n负薪登险过长林,\n沿途荆棘却见金。\n若还要问姻缘事,\n梅花一度尽风情。","image_path":".protected_data/processed/平齐式/1.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":1},{"id":"平齐式-2","name":"孝服香","category":"平齐式","style_description":"右炷香灰右弯,其余直立。","meaning_poem":"孝服香号传噩耗,\n寸肠欲断泪滔滔。\n七日之内伤人口,\n孤魂野鬼不肯饶。\n大人躲过防少小,\n家人幸免族亲找。","image_path":".protected_data/processed/平齐式/2.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":2},{"id":"平齐式-3","name":"沉吟香","category":"平齐式","style_description":"右炷香灰左弯,其余直立。","meaning_poem":"沉吟香号有疑难,\n迟迟不决主意乱。\n恩中成怨既如是,\n何必心中作缠绵。\n清贫浊富知在天,\n谁知有路上钓船。","image_path":".protected_data/processed/平齐式/3.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":3},{"id":"平齐式-4","name":"营利香","category":"平齐式","style_description":"左炷香灰右弯,其余直立。","meaning_poem":"营利香号报喜音,\n商贾谋求日日新。\n好似凿山见美玉,\n好比掘地见黄金。\n记得东华分造化,\n何虑万事不由心。","image_path":".protected_data/processed/平齐式/4.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":4},{"id":"平齐式-5","name":"天赁香","category":"平齐式","style_description":"右炷香灰直立,其余左弯。","meaning_poem":"天赁香号主赁出,\n或是店铺或房屋。\n或是权利或是物,\n或是转手或出租。\n倘若能否落实处,\n勘对生克自清楚。","image_path":".protected_data/processed/平齐式/5.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":5},{"id":"平齐式-6","name":"周恤香","category":"平齐式","style_description":"左炷香灰直立,其余右弯。","meaning_poem":"周恤香号主周济,\n悲心救苦发菩提。\n近日定有亲友来。\n上门找借求助力。\n善知若肯给帮助,\n种就福田及后裔。","image_path":".protected_data/processed/平齐式/6.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":6},{"id":"平齐式-7","name":"天龟香","category":"平齐式","style_description":"左炷香灰直立,其余左弯。","meaning_poem":"天龟香号主成功,\n谋望可期凭持重,\n持身严正有分寸,\n持之有故且有恒,\n善知张弛自有数,\n何必焚香问天公。","image_path":".protected_data/processed/平齐式/7.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":7},{"id":"平齐式-8","name":"太平香","category":"平齐式","style_description":"右炷香灰直立,其余右弯。","meaning_poem":"太平香号主平安,\n一曲笙歌唱丰年。\n人在花间明月下,\n男婚女嫁寡配鳏。\n粉墙门外柳交春,\n儿孙绕膝伴幽闲。","image_path":".protected_data/processed/平齐式/8.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":8},{"id":"平齐式-9","name":"安身香","category":"平齐式","style_description":"左炷香灰直立,其余内弯。","meaning_poem":"安身香号劝知君,\n操持谨守承家训。\n纵然境况多困窘,\n命里无有勿妄寻。\n何期刘郎望得志,\n小富即安可依循。","image_path":".protected_data/processed/平齐式/9.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":9},{"id":"平齐式-10","name":"安逸香","category":"平齐式","style_description":"右炷香灰直立,其余内弯。","meaning_poem":"安逸香号喜心间,\n心善到头终必安。\n半身乡井身未闲,\n功成身退归家园。\n反覆儿女几局棋,\n措置安排足心愿。","image_path":".protected_data/processed/平齐式/10.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"平","ash":"直立"}},"index":10},{"id":"平齐式-11","name":"天俊香","category":"平齐式","style_description":"右炷香灰直立,其余外弯。","meaning_poem":"天侯香号主等待,\n待机行事须挨耐。\n时不来兮空用心,\n运若到时消息来。\n试看后园花果树,\n晚来丹桂绽蕾开。","image_path":".protected_data/processed/平齐式/11.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"平","ash":"直立"}},"index":11},{"id":"平齐式-12","name":"天祀香","category":"平齐式","style_description":"左炷香灰直立,其余外弯。","meaning_poem":"天祀香号主祭祀,\n祀天祀孔祀祖祠。\n三牲供品须齐备,\n鲜花果酒要应时。\n感念天地和祖宗,\n好培福荫庇后嗣。","image_path":".protected_data/processed/平齐式/12.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":12},{"id":"平齐式-13","name":"挫折香","category":"平齐式","style_description":"中炷香灰直立,其余外弯。","meaning_poem":"挫折香号主挫折,\n非事既身遭灾殃。\n谋事受制有挫伤,\n跌仆磕碰筋骨伤。\n若问岂期出险关,\n自有高人为主张。","image_path":".protected_data/processed/平齐式/13.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"外弯"}},"index":13},{"id":"平齐式-14","name":"宾客香","category":"平齐式","style_description":"中炷香灰直立,其余内弯。","meaning_poem":"宾客香号会宾朋,\n七日之内喜相逢。\n久别亲朋不相聚,\n同事小酌论前程。\n休怪鹏鹏相背立,\n月老高人送春风。","image_path":".protected_data/processed/平齐式/14.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"内弯"}},"index":14},{"id":"平齐式-15","name":"天济香","category":"平齐式","style_description":"中炷香灰左弯,其余直立。","meaning_poem":"天济香号主赈灾,\n朝廷传旨遣钦差。\n各业富豪善男女,\n捐赠衣物和钱财。\n一文两贯人心在,\n赈济灾民献慈爱。","image_path":".protected_data/processed/平齐式/15.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":15},{"id":"平齐式-16","name":"天安香","category":"平齐式","style_description":"中炷香灰右弯,其余直立。","meaning_poem":"天安香号劝世人,\n规矩老实守本分。\n既或困顿多磨难,\n安身立命做善人。\n立志欲求终久事,\n前程须忌涉水深。","image_path":".protected_data/processed/平齐式/16.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":16},{"id":"平齐式-17","name":"天抚香","category":"平齐式","style_description":"中炷香灰直立,其余左弯。","meaning_poem":"天抚香号主抚慰,\n困难重重遇豪贵。\n从前捉襟却见肘,\n如今如鱼又得水。\n倘若知君是富豪,\n怜贫济困堪可为。\n17","image_path":".protected_data/processed/平齐式/17.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":17},{"id":"平齐式-18","name":"天宁香","category":"平齐式","style_description":"中炷香灰直立,其余右弯。","meaning_poem":"天宁香号主安宁,\n小院人家好风景。\n半甜半苦曾经过,\n多虑多愁也曾经。\n逢时正在看如今,\n多虑多愁也曾经。","image_path":".protected_data/processed/平齐式/18.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":18},{"id":"平齐式-19","name":"自力香","category":"平齐式","style_description":"左炷香灰左弯,其余右弯。","meaning_poem":"自力香号主自强,\n自强不息志坚刚。\n求学求婚靠自己,\n经营立业不依傍。\n自给自足兴家业,\n笃信耕锄必打粮。","image_path":".protected_data/processed/平齐式/19.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":19},{"id":"平齐式-20","name":"天秤香","category":"平齐式","style_description":"右炷香灰右弯,其余左弯。","meaning_poem":"天秤香号动资产,\n牲畜土地或房产。\n或买或卖或租赁,\n或是儿女怎分摊。\n惟恐个中有纠缠,\n公平契约是关键。","image_path":".protected_data/processed/平齐式/20.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":20},{"id":"平齐式-21","name":"安定香","category":"平齐式","style_description":"左炷香灰右弯,其余内弯。","meaning_poem":"安定香号主安宁,\n国泰民安逐时新。\n居家得意玉楼春,\n商贾盈利得黄金。\n知音正好同携手,\n两树开花子业兴。","image_path":".protected_data/processed/平齐式/21.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":21},{"id":"平齐式-22","name":"藤金香","category":"平齐式","style_description":"右炷香灰左弯,其余内弯。","meaning_poem":"藤金香号说生意,\n大家凑钱谋利益。\n借问合伙宜不宜,\n但凭香火看利弊。\n三炷明亮是相宜,\n若见昏暗必失利。","image_path":".protected_data/processed/平齐式/22.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":22},{"id":"平齐式-23","name":"奏疏香","category":"平齐式","style_description":"右炷香灰左弯,其余外弯。","meaning_poem":"奏疏香号主奏章,\n臣向皇帝表主张。\n纷纷计谋安家邦,\n整理田园振家乡。\n奏折未必呈君王,\n家事家常好商量。","image_path":".protected_data/processed/平齐式/23.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":23},{"id":"平齐式-24","name":"安乐香","category":"平齐式","style_description":"左炷香灰右弯,其余外弯。","meaning_poem":"安乐香号喜乐多,\n女嫁男婚好吟歌。\n家声名利锦绣中,\n寿元高稳人事和。\n百年后事问如何,\n子孙相伴福自多。","image_path":".protected_data/processed/平齐式/24.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":24},{"id":"平齐式-25","name":"平等香","category":"平齐式","style_description":"三炷香灰左弯。","meaning_poem":"平等香号赞开明,\n平等待人价黄金。\n夫妻恩爱长厮守,\n同群到老亦知音。\n举事随缘易合伙,\n发迹全凭结同心。","image_path":".protected_data/processed/平齐式/25.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":25},{"id":"平齐式-26","name":"天侔香","category":"平齐式","style_description":"三炷香灰右弯。","meaning_poem":"天侔香号主相安,\n甘苦相济共患难。\n夫妻相敬比孟梁。\n同道亲密更无间。\n童叟无欺好经营,\n同病相怜相助授。","image_path":".protected_data/processed/平齐式/26.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":26},{"id":"平齐式-27","name":"天休香","category":"平齐式","style_description":"左炷香灰直立,其余搭桥。","meaning_poem":"天休香号无成就,\n风景萧疏落叶秋。\n目前有件踌躇事,\n百样思量百样愁。\n若要谋坐经营客,\n有名无实本难收。","image_path":".protected_data/processed/平齐式/27.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":27},{"id":"平齐式-28","name":"天滞香","category":"平齐式","style_description":"右炷香灰直立,其余搭桥。","meaning_poem":"天滞香号主滞留,\n百种迂回不自由。\n经营滞销难销售,\n百般揩置笑成忧。\n宗族拖累散资财,\n亲识维系却如仇。","image_path":".protected_data/processed/平齐式/28.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"直立"}},"index":28},{"id":"平齐式-29","name":"抽丁香","category":"平齐式","style_description":"左炷香灰左弯,其余搭桥。","meaning_poem":"抽丁香号主兵役,\n戎马生涯当志气。\n雁过关山去路远,\n孤飞别宿有谁期。\n虽然吴越知音少,\n江山磨节可相依。","image_path":".protected_data/processed/平齐式/29.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":29},{"id":"平齐式-30","name":"重孝香","category":"平齐式","style_description":"右炷香灰右弯,其余搭桥。","meaning_poem":"重孝香号穿孝服,\n当有重孝放声哭。\n一年之内难躲过,\n不死生父死生母。\n倘然免得灾星过,\n除非超拔诵浮屠。","image_path":".protected_data/processed/平齐式/30.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"右弯"}},"index":30},{"id":"平齐式-31","name":"拜盟香","category":"平齐式","style_description":"左炷香灰右弯,其余搭桥。","meaning_poem":"拜盟香号主结义,\n兄弟同心又协力。\n狂风骤雨伴知音,\n敢留清明为品题。\n掀天揭地成功日,\n两两相逐上云梯。","image_path":".protected_data/processed/平齐式/31.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":31},{"id":"平齐式-32","name":"凶信香","category":"平齐式","style_description":"右炷香灰左弯,其余搭桥。","meaning_poem":"凶信香号主悲痛,\n死亡消息传家中。\n倘若家人安无恙,\n谨防三日煞气重。\n挨过三日无损伤,\n定是神明护佑功。","image_path":".protected_data/processed/平齐式/32.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"左弯"}},"index":32},{"id":"平齐式-33","name":"金阙香","category":"平齐式","style_description":"三炷香灰搭桥。","meaning_poem":"金阙香号主偏财,\n无意之中金玉来。\n着意栽花花苞懒,\n无意赏花花朵开。\n雀巢生凤引彩凰,\n寒门挺出栋梁材。","image_path":".protected_data/processed/平齐式/33.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":33},{"id":"平齐式-34","name":"齐天香","category":"平齐式","style_description":"三炷香灰直立。","meaning_poem":"齐天香号主安康\n俗称也叫平安香。\n求得此香是善缘,\n家宅平安无惆怅。\n口舌不犯自心宽,\n老少欢乐身无羌。","image_path":".protected_data/processed/平齐式/34.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":34},{"id":"左斜切式-1","name":"圆满香","category":"左斜切式","style_description":"左炷香灰左弯,其余直立。","meaning_poem":"圆满香号无缺憾,\n大事小事皆圆满。\n若求驾侣有宿缘,\n既是破镜又重圆。\n倘然善知修功德,\n闲笑浮屠问阿难。","image_path":".protected_data/processed/左斜切式/1.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":1},{"id":"左斜切式-2","name":"蝇头香","category":"左斜切式","style_description":"右炷香灰右弯,其余直立。","meaning_poem":"蝇头香号力微薄,\n营生费力苦奔波。\n求财谋利不得利,\n蝇头蛇尾将就作。\n求学求官受挫折,\n家境贫寒好窘迫。","image_path":".protected_data/processed/左斜切式/2.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":2},{"id":"左斜切式-3","name":"荫庇香","category":"左斜切式","style_description":"右炷灰左弯,其余直立。","meaning_poem":"荫庇香号得祖荫,好似大树有遮荫。成事靠亲靠父母,发处因祖功德因。倘若强说凭自立,低头自扪问良心。","image_path":".protected_data/processed/左斜切式/3.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":3},{"id":"左斜切式-4","name":"退隐香","category":"左斜切式","style_description":"左炷香灰右弯,其余直立。","meaning_poem":"退隐香号主隐居,为官退职势所趋。自此不问官家事,识得权钱名利益。纵然不是官场人,定与辞退相干系。","image_path":".protected_data/processed/左斜切式/4.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":4},{"id":"左斜切式-5","name":"无为香","category":"左斜切式","style_description":"右炷香灰直立,其余左弯。","meaning_poem":"无为香号非无能,\n亦非人事无适从。\n顺其自然随缘份,\n无为而治方有功。\n世人都说是消及,\n那知无为自从容。","image_path":".protected_data/processed/左斜切式/5.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":5},{"id":"左斜切式-6","name":"禅机香","category":"左斜切式","style_description":"左炷香灰直立,其余右弯。","meaning_poem":"禅机香号玄机透,\n今日禅机作话头。\n亦有亦无无亦有,\n非有非无无非有。\n聚散皆是因缘定,\n贫富自己问根由。","image_path":".protected_data/processed/左斜切式/6.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":6},{"id":"左斜切式-7","name":"报德香","category":"左斜切式","style_description":"左炷香灰直立,其余左弯。","meaning_poem":"报德香号念深恩,\n三重恩德记得真。\n天地吾佛和父母,\n恩情难报是我身。\n知恩报德何所求,\n顺孝畏慎自通神。","image_path":".protected_data/processed/左斜切式/7.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":7},{"id":"左斜切式-8","name":"放生香","category":"左斜切式","style_description":"右炷香灰直立,其余右弯。","meaning_poem":"放生香号积阴功,\n信佛人家佛田种。\n小小动物鸟鱼虫,\n放归自然去求生。\n尔等不信因果报,\n今生受者是见证。","image_path":".protected_data/processed/左斜切式/8.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":8},{"id":"左斜切式-9","name":"报恩香","category":"左斜切式","style_description":"左炷香灰直立,其余内弯。","meaning_poem":"报恩香号见真情,\n知恩勇报堪可评。\n受人恩惠是福德,\n知恩不报无人性。\n善知今日自亨通,\n当把贵人来追寻。","image_path":".protected_data/processed/左斜切式/9.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":9},{"id":"左斜切式-10","name":"皈依香","category":"左斜切式","style_description":"右炷香灰直立,其余内弯。","meaning_poem":"皈依香号主修行,\n而今指路谢神明。\n一声佛号一声心,\n皈依三宝修心性。\n扫除身内贪嗔痴,\n修成来世真清净。","image_path":".protected_data/processed/左斜切式/10.png","features":{"left_candle":{"height":"低","ash":"内弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"平","ash":"直立"}},"index":10},{"id":"左斜切式-11","name":"天贵香","category":"左斜切式","style_description":"右炷香灰直立,其余外弯。","meaning_poem":"天贵香号主富贵,满园天桃彩蝶飞。虽然傲雪凌霜久,终见春日又光辉。得子全凭神保佑,平生心志己相随。","image_path":".protected_data/processed/左斜切式/11.png","features":{"left_candle":{"height":"低","ash":"外弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"平","ash":"直立"}},"index":11},{"id":"左斜切式-12","name":"无题香","category":"左斜切式","style_description":"左炷香灰直立,其余外弯。","meaning_poem":"无题香号本无意,无意之中透玄机。\n无似山林静思禅,有如烟波跃鲤鱼。\n无缘无故不须猜,有缘有情定可依。","image_path":".protected_data/processed/左斜切式/12.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":12},{"id":"左斜切式-13","name":"解脱香","category":"左斜切式","style_description":"中炷香灰直立,其余外弯。","meaning_poem":"解脱香号离苦海,\n放下无明扫尘埃。\n说来轻巧做时难,\n明心见性观自在。\n只要真心修大道,\n身边琐事本无碍。","image_path":".protected_data/processed/左斜切式/13.png","features":{"left_candle":{"height":"低","ash":"外弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"外弯"}},"index":13},{"id":"左斜切式-14","name":"逍遥香","category":"左斜切式","style_description":"中炷香灰直立,其余内弯。","meaning_poem":"逍遥香号心性巧,\n因人待势人缘好。\n临灾遇险无伤害,\n世事艰难遇贵豪。\n春光试问有多少,\n黄金白玉非为宝。","image_path":".protected_data/processed/左斜切式/14.png","features":{"left_candle":{"height":"低","ash":"内弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"内弯"}},"index":14},{"id":"左斜切式-15","name":"报施香","category":"左斜切式","style_description":"中炷香灰左弯,其余直立。","meaning_poem":"报施香号功德高,虔诚信佛真修道。平生怜贫好施舍,为人做事不求报。善知若问身边事,自有神明暗中保。","image_path":".protected_data/processed/左斜切式/15.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":15},{"id":"左斜切式-16","name":"承恩香","category":"左斜切式","style_description":"中炷香灰右弯,其余直立。","meaning_poem":"承恩香号沐皇恩,重荣重禄受恩深。禄重终须掌权印,财多惟虑祸临身。善念与天相契合,正直清廉怕个甚。","image_path":".protected_data/processed/左斜切式/16.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":16},{"id":"左斜切式-17","name":"超度香","category":"左斜切式","style_description":"中炷香灰直立,其余左弯。","meaning_poem":"超度香号消业力,六道轮回果不虚。世人得遇凶化吉,脱离苦难乐安居。阴人得此指引缘,驾鹤携琴西方去。","image_path":".protected_data/processed/左斜切式/17.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":17},{"id":"左斜切式-18","name":"朝山香","category":"左斜切式","style_description":"中炷香灰直立,其余右弯。","meaning_poem":"朝山香号积功德,好培善福来因果。若令善知真消息,名人寺庙进香火。或佛或道来参拜,一点灵光振家国。","image_path":".protected_data/processed/左斜切式/18.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":18},{"id":"左斜切式-19","name":"困厄香","category":"左斜切式","style_description":"左炷香灰左弯,其余右弯。","meaning_poem":"困厄香号主蹉跎,财帛虚耗事多磨。休问男婚女嫁事,原来误入虎狼窝。忍耐非为是上策。改弦易辙方解脱。","image_path":".protected_data/processed/左斜切式/19.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":19},{"id":"左斜切式-20","name":"吉庆香","category":"左斜切式","style_description":"右炷香灰右弯,其余左弯。","meaning_poem":"吉庆香号传佳音,不意之中喜煞人。往日有意花须谢,今日无心柳布荫。彩门久待来奇玉,推枕拥衾称夙心。","image_path":".protected_data/processed/左斜切式/20.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":20},{"id":"左斜切式-21","name":"沉迷香","category":"左斜切式","style_description":"左炷香灰右弯,其余内弯。","meaning_poem":"沉迷香号主痴情,若男若女太任性。明知满堂风雨恶,偏向污浊水边行。碌碌区区心未了,谁知梦里何时醒。","image_path":".protected_data/processed/左斜切式/21.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":21},{"id":"左斜切式-22","name":"咸池香","category":"左斜切式","style_description":"右炷香灰左弯,其余内弯。","meaning_poem":"咸池香号惹风骚,若男若女命里招。男子好色眠花柳,女子贪淫偷卖俏。若问鸳鸯伴侣事,抱定琵琶身难靠。","image_path":".protected_data/processed/左斜切式/22.png","features":{"left_candle":{"height":"低","ash":"内弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":22},{"id":"左斜切式-23","name":"打诨香","category":"左斜切式","style_description":"右炷香灰左弯,其余外弯。","meaning_poem":"打诨香号打哈哈,\n无聊逗趣作笑话。\n本来风光来潇洒,\n焚香作揖求个啥。\n平白无事问君评,\n何必强奸神作答。","image_path":".protected_data/processed/左斜切式/23.png","features":{"left_candle":{"height":"低","ash":"外弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":23},{"id":"左斜切式-24","name":"乌有香","category":"左斜切式","style_description":"左炷香灰右弯,其余外弯。","meaning_poem":"乌有香号主虚幻,子虚乌有若梦间。所言所述不存在,所求所望难实现。即使事成既已得。化为乌有还消散。","image_path":".protected_data/processed/左斜切式/24.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":24},{"id":"左斜切式-25","name":"催丹香","category":"左斜切式","style_description":"三炷香灰左弯。","meaning_poem":"催丹香号炼心性,以德修身养性命。修者温炉运金丹,物外安身不染病。倘然不是修行人,善种福田是聪明。","image_path":".protected_data/processed/左斜切式/25.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":25},{"id":"左斜切式-26","name":"催命香","category":"左斜切式","style_description":"三炷香灰右弯。","meaning_poem":"催命香号闻哭啼,黑白无常来去急。地府阎罗催寿命,梦魂难牵半月里。不见老死伤人口,罹难缠身自凄凄。","image_path":".protected_data/processed/左斜切式/26.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":26},{"id":"左斜切式-27","name":"鬼愁香","category":"左斜切式","style_description":"左炷香灰直立,其余搭桥。","meaning_poem":"鬼魅香号招鬼怪,\n七日之内必有灾。\n大人小孩不安宁,\n横事不来灾病来。\n假若求安快祷告,\n请师作法免灾害。","image_path":".protected_data/processed/左斜切式/27.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":27},{"id":"左斜切式-28","name":"残疾香","category":"左斜切式","style_description":"右炷香灰直立,其余搭桥。","meaning_poem":"残疾香号主伤残,\n当知防患于未然。\n假若今生有缺陷,\n前世因果今生验。\n应信慈悲多施舍,\n来世人天定福安。","image_path":".protected_data/processed/左斜切式/28.png","features":{"left_candle":{"height":"低","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"直立"}},"index":28},{"id":"左斜切式-29","name":"太岁香","category":"左斜切式","style_description":"左炷香灰左弯,其余搭桥。","meaning_poem":"太岁香号时运背,只因时年犯太岁。事到成处变灾危,身前世事尽成非。山高水远迷归路,怕冷鸳鸯夜半飞。","image_path":".protected_data/processed/左斜切式/29.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":29},{"id":"左斜切式-30","name":"怄气香","category":"左斜切式","style_description":"右炷香灰右弯,其余搭桥。","meaning_poem":"怄气香号主不满,事事学知遇麻烦。与人生气闹别扭,争持吵架闹翻脸。究竟哪些不合意,说来道去是扯闲。","image_path":".protected_data/processed/左斜切式/30.png","features":{"left_candle":{"height":"低","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"右弯"}},"index":30},{"id":"左斜切式-31","name":"阅墙香","category":"左斜切式","style_description":"左炷香灰右弯,其余搭桥。","meaning_poem":"阅墙香号起风波,\n兄弟争吵动干戈。\n不是赡养有争议,\n便是喜庆挑剔多。\n倘若不是为家产,\n婆媳邻里定不和。","image_path":".protected_data/processed/左斜切式/31.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":31},{"id":"左斜切式-32","name":"鼎峙香","category":"左斜切式","style_description":"右炷香灰左弯,其余搭桥。","meaning_poem":"鼎峙香号主对立,\n势成三足相鼎立。\n古有三国魏蜀吴,\n今日尔等涉生意。\n若问目前凶与吉,\n三国归晋难为你。","image_path":".protected_data/processed/左斜切式/32.png","features":{"left_candle":{"height":"低","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"左弯"}},"index":32},{"id":"左斜切式-33","name":"暴卒香","category":"左斜切式","style_description":"三炷香灰搭桥。","meaning_poem":"暴卒香号主嚎啕,卒死夭亡寿数到。方才行坐有说笑,须臾西去世情抛。车祸脑血早排定,自己不去无常叫。","image_path":".protected_data/processed/左斜切式/33.png","features":{"left_candle":{"height":"低","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":33},{"id":"左斜切式-34","name":"功德香","category":"左斜切式","style_description":"三炷香灰直立。","meaning_poem":"功德香号多盖益,麒麟入梦显威仪。嘉言懿行子孙效,合家欢乐百事吉。且喜神明来点化,智勇才达传美誉。","image_path":".protected_data/processed/左斜切式/34.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":34},{"id":"左平齐式-1","name":"淘金香","category":"左平齐式","style_description":"左炷香灰左弯,其余直立。","meaning_poem":"淘金香号主辛劳,\n沙里淘金终获宝。\n倘问儿女前程事,\n莫向天宫觅仙桃。\n松竹林里后桑园,\n自有遂心如意草。","image_path":".protected_data/processed/左平齐式/1.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"高","ash":"直立"}},"index":1},{"id":"左平齐式-2","name":"凄凉香","category":"左平齐式","style_description":"右炷香灰右弯,其余直立。","meaning_poem":"凄凉香号处境难,\n家事身事苦难言。\n鳏寡孤霜伴灯眠,\n怨男怨女枕衾寒。\n勾勾绞绞扯不清,\n不见争讼亦罗乱。","image_path":".protected_data/processed/左平齐式/2.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"高","ash":"右弯"}},"index":2},{"id":"左平齐式-3","name":"酒色香","category":"左平齐式","style_description":"右炷香灰左弯,其余直立。","meaning_poem":"酒色香号迷酒色,多因诱惑不肯舍。劝尔尚有知音在,知轻识重善斟酌。早向前程行好事,回头谨守无危厄。","image_path":".protected_data/processed/左平齐式/3.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"高","ash":"左弯"}},"index":3},{"id":"左平齐式-4","name":"避讳香","category":"左平齐式","style_description":"左炷香灰右弯,其余直立。","meaning_poem":"避讳香号防忧患,犹如艄公忌说”翻”。善知今岁是凶年,天克地冲查年干。五行占类记心间,忌讳棺椁避蛇犬。","image_path":".protected_data/processed/左平齐式/4.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"高","ash":"直立"}},"index":4},{"id":"左平齐式-5","name":"长生香","category":"左平齐式","style_description":"右炷香灰直立,其余左弯。","meaning_poem":"长生香号自从容,\n清风名节承家重。\n恐教晚来身不爽,\n休疑平生沾阴功。\n营家壮力十分劳,\n父子同荣振家声。","image_path":".protected_data/processed/左平齐式/5.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"高","ash":"直立"}},"index":5},{"id":"左平齐式-6","name":"残照香","category":"左平齐式","style_description":"左炷香灰直立,其余右弯。","meaning_poem":"残照香号夕阳照,\n风爽只因金秋到。\n莫叹花谢人亦老,\n冬雪梅花更娇娆。\n鸥鹭晚来同乐处,\n夕阳拱照消息好。","image_path":".protected_data/processed/左平齐式/6.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"高","ash":"右弯"}},"index":6},{"id":"左平齐式-7","name":"无能香","category":"左平齐式","style_description":"左炷香灰直立,其余左弯。","meaning_poem":"无能香号无能为,\n不学无术怨得谁。\n而今问佛佛不语,\n问神问仙反怪罪。\n若然还问所求事,\n磕破头颅也白费。","image_path":".protected_data/processed/左平齐式/7.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"高","ash":"左弯"}},"index":7},{"id":"左平齐式-8","name":"薄命香","category":"左平齐式","style_description":"右炷香灰直立,其余右弯。","meaning_poem":"薄命香号多磨难。\n饱经风霜立业艰。\n幸有鸳鸯好伴侣,\n谁料雨打霜又寒。\n人家门前报好音,\n我枉身心憾事连。","image_path":".protected_data/processed/左平齐式/8.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"高","ash":"直立"}},"index":8},{"id":"左平齐式-9","name":"宽恕香","category":"左平齐式","style_description":"左炷香灰直立,其余内弯。","meaning_poem":"宽恕香号多原谅,毫不计较互谦让。善知知事己做错,何必指责索赔偿。亲亲友友是一家,体谅包容仁义长。","image_path":".protected_data/processed/左平齐式/9.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"高","ash":"内弯"}},"index":9},{"id":"左平齐式-10","name":"子息香","category":"左平齐式","style_description":"右炷香灰直立,其余内弯。","meaning_poem":"子息香号说子嗣,盼儿盼女日迟迟。盼来儿女成冤家,好如灯烛蚕作丝。嗟叹儿女不得济,何必疯心盼儿子。","image_path":".protected_data/processed/左平齐式/10.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"高","ash":"直立"}},"index":10},{"id":"左平齐式-11","name":"天恣香","category":"左平齐式","style_description":"右炷香灰直立,其余外弯。","meaning_poem":"天恣香号主胡为,放纵骄横无法规。若问那个人恣睢,不问自己还问谁。堪叹娇生惯养成,不撞南墙头不回。","image_path":".protected_data/processed/左平齐式/11.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"高","ash":"直立"}},"index":11},{"id":"左平齐式-12","name":"天遁香","category":"左平齐式","style_description":"左炷香灰直立,其余外弯。","meaning_poem":"天遁香号隐踪迹,遁世埋名好休息。莫论成败与艰辛,莫谈儿女怎得济。唤醒当时再少年,清风明月为知己。","image_path":".protected_data/processed/左平齐式/12.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"高","ash":"外弯"}},"index":12},{"id":"左平齐式-13","name":"怡悦香","category":"左平齐式","style_description":"中炷香灰直立,其余外弯。","meaning_poem":"怡悦香号百事强,衣食丰足乐小康。屋内黄金不用量,任凭旁人说短长。问尔去路兴亡事,梅花雪里溢芳香。","image_path":".protected_data/processed/左平齐式/13.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"高","ash":"外弯"}},"index":13},{"id":"左平齐式-14","name":"衔恨香","category":"左平齐式","style_description":"中炷香灰直立,其余内弯。","meaning_poem":"衔恨香号主伤神,\n恨事重重不离身。\n欲趋欲就碍越超,\n藕断丝连却深沉。\n劝尔多愁善感人,\n扯断缠绵拭泪痕。","image_path":".protected_data/processed/左平齐式/14.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"高","ash":"内弯"}},"index":14},{"id":"左平齐式-15","name":"作艺香","category":"左平齐式","style_description":"中炷香灰左弯,其余直立。","meaning_poem":"作艺香号主演出,展露才华和艺术。假若善知非艺人,学时品行比松竹。生身好似种杨柳,只待杨柳成荫处。","image_path":".protected_data/processed/左平齐式/15.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"高","ash":"直立"}},"index":15},{"id":"左平齐式-16","name":"捷报香","category":"左平齐式","style_description":"中炷香灰右弯,其余直立。","meaning_poem":"捷报香号主喜讯,劳心与业共佳音。田中五谷庆丰登,戎马出征建功勋。倘若一个商贾客,满堂金玉又重新。","image_path":".protected_data/processed/左平齐式/16.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"高","ash":"直立"}},"index":16},{"id":"左平齐式-17","name":"沉浮香","category":"左平齐式","style_description":"中炷香灰直立,其余左弯。","meaning_poem":"沉浮香号看仕途,\n云海迢迢关山路。\n若问前程荣枯事,\n雨里天桃风里烛。\n承然田地好归耕,\n野渡横舟莺出谷。","image_path":".protected_data/processed/左平齐式/17.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"高","ash":"左弯"}},"index":17},{"id":"左平齐式-18","name":"宝偈香","category":"左平齐式","style_description":"中炷香灰直立,其余右弯。","meaning_poem":"宝偈香号胜天书,劝人在世莫贪图。名利拘身自寻苦,恩禄天然乐自如。谁信轮回因果报,几番谋算终须无。","image_path":".protected_data/processed/左平齐式/18.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"高","ash":"右弯"}},"index":18},{"id":"左平齐式-19","name":"薄情香","category":"左平齐式","style_description":"左炷香灰左弯,其余右弯。","meaning_poem":"薄情香号主无义,犹畏悠悠雨凄凄。堪叹鸳鸯交颈处,不知风雨骤相欺。倘然识得真面目,何必帘内自悲戚。","image_path":".protected_data/processed/左平齐式/19.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"高","ash":"右弯"}},"index":19},{"id":"左平齐式-20","name":"智慧香","category":"左平齐式","style_description":"左炷香灰右弯,其余左弯。","meaning_poem":"智慧香号主聪明,智谋才略堪可评。善知创造有发明,人人夸尔智多星。若还问个名利事,何必举头问神明。","image_path":".protected_data/processed/左平齐式/20.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"高","ash":"左弯"}},"index":20},{"id":"左平齐式-21","name":"琐碎香","category":"左平齐式","style_description":"左炷香灰右弯,其余内弯。","meaning_poem":"琐碎香号繁绊多,\n任尔周旋苦斟酌。\n图名谋利成萧索,事业迂回又蹉跎。\n还了许多业力债,\n无心岁月方解脱。","image_path":".protected_data/processed/左平齐式/21.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"高","ash":"内弯"}},"index":21},{"id":"左平齐式-22","name":"友善香","category":"左平齐式","style_description":"右炷香灰左弯,其余内弯。","meaning_poem":"友善香号主亲和,\n素相友好不生祸。\n出行得遇知音助,\n举措朋友帮忙伙。\n友好和睦共相处,\n纵有艰难能闯过。","image_path":".protected_data/processed/左平齐式/22.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"高","ash":"左弯"}},"index":22},{"id":"左平齐式-23","name":"回春香","category":"左平齐式","style_description":"右炷香灰左弯,其余外弯。","meaning_poem":"回春香号医术高,妙手回春人称道。善知修来好因果,疾患自得好医疗。若问人事生意事,冬去春来春光好。","image_path":".protected_data/processed/左平齐式/23.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"高","ash":"左弯"}},"index":23},{"id":"左平齐式-24","name":"颐养香","category":"左平齐式","style_description":"左炷香灰右弯,其余外弯。","meaning_poem":"颐养香号主养生,人老珠黄笑春风。堪叹善知会修性,滋润筋骨肯作功。劝尔留意更殷勤,独占寒衾亦融融。","image_path":".protected_data/processed/左平齐式/24.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"高","ash":"外弯"}},"index":24},{"id":"左平齐式-25","name":"沉冤香","category":"左平齐式","style_description":"三炷香灰左弯。","meaning_poem":"沉冤香号苦难言,蒙冤有口难申辨。生来本分怕惹事,偏遇奸人弄强权。善知何日冤昭雪,香燃七分自明断。","image_path":".protected_data/processed/左平齐式/25.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"高","ash":"左弯"}},"index":25},{"id":"左平齐式-26","name":"妙德香","category":"左平齐式","style_description":"三炷香灰右弯。","meaning_poem":"妙德香号添欢喜,恰似桃花带春雨。只缘善别贤与愚,能分皂白会舍取。千方百计巧经营,事事遂心尽得意。","image_path":".protected_data/processed/左平齐式/26.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"高","ash":"右弯"}},"index":26},{"id":"左平齐式-27","name":"减禄香","category":"左平齐式","style_description":"左炷香灰直立,其余搭桥。","meaning_poem":"减禄香号禄马摇,腰金衣紫亦孬遭。不是为官不检点,定是无庸丢纱帽。三分小人来作祟,七分自己业力找。","image_path":".protected_data/processed/左平齐式/27.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"高","ash":"搭桥"}},"index":27},{"id":"左平齐式-28","name":"增禄香","category":"左平齐式","style_description":"右炷香灰直立,其余搭桥。","meaning_poem":"增禄香号禄马到,龙飞凤舞架虹桥。为官为宦定升迁,平民百姓好运交。但记神前空许愿,好兆亦是皂角泡。","image_path":".protected_data/processed/左平齐式/28.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"高","ash":"直立"}},"index":28},{"id":"左平齐式-29","name":"兵变香","category":"左平齐式","style_description":"左炷香灰左弯,其余搭桥。","meaning_poem":"兵变香号主祸乱,\n叛逆骚乱有内奸。\n假如不是军营里,\n军营动荡亦不安。\n小人骚乱生灾害,\n怎奈风光不如前。","image_path":".protected_data/processed/左平齐式/29.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"高","ash":"搭桥"}},"index":29},{"id":"左平齐式-30","name":"幸免香","category":"左平齐式","style_description":"右炷香灰右弯,其余搭桥。","meaning_poem":"幸免香号主侥幸,\n幸免于难谢神明。\n可喜可贺三日内,\n福祸吉凶天排定。\n遇险不险惟独你,\n失而复得有虚惊。","image_path":".protected_data/processed/左平齐式/30.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"高","ash":"右弯"}},"index":30},{"id":"左平齐式-31","name":"刀兵香","category":"左平齐式","style_description":"左炷香灰右弯,其余搭桥","meaning_poem":"刀兵香号动刀枪,\n干戈平地起萧墙。\n不是边陲战火起。\n便是内地犯劫抢。\n纵然天下无乱事,\n兄弟邻里互骂娘。","image_path":".protected_data/processed/左平齐式/31.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"高","ash":"搭桥"}},"index":31},{"id":"左平齐式-32","name":"恻隐香","category":"左平齐式","style_description":"右炷香灰左弯,其余搭桥。","meaning_poem":"恻隐香号主悲怜,\n同情苦难心慈善。\n孤儿寡母到眼前,\n肯舍衣食肯舍钱。\n若问自身所求事,\n我佛大悲更垂怜。","image_path":".protected_data/processed/左平齐式/32.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"高","ash":"左弯"}},"index":32},{"id":"左平齐式-33","name":"报复香","category":"左平齐式","style_description":"三炷香灰搭桥。","meaning_poem":"报复香号主相害,冤仇易结不意开。一个仗势逞淫威,一个心直口又快。若还要问何日了,邪恶如何根本在。","image_path":".protected_data/processed/左平齐式/33.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"高","ash":"搭桥"}},"index":33},{"id":"左平齐式-34","name":"天地香","category":"左平齐式","style_description":"三炷香灰直立。","meaning_poem":"天地香号祥云绕,天地采香鸿运交。急焚香火勿怠慢,多积功德始坚牢。嫁娶遂心生意好,合家喜庆磨难消。","image_path":".protected_data/processed/左平齐式/34.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"高","ash":"直立"}},"index":34},{"id":"右平齐式-1","name":"天罡香","category":"右平齐式","style_description":"左炷香灰左弯,其余直立。","meaning_poem":"天罡香号不一般,\n粼粼北光星光灿。\n堪赞善知天骄子,\n天分天姿有天缘。\n阴功相助前程远,\n名流家声振空前。","image_path":".protected_data/processed/右平齐式/1.png","features":{"left_candle":{"height":"高","ash":"左弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":1},{"id":"右平齐式-2","name":"峥嵘香","category":"右平齐式","style_description":"右炷香灰右弯,其余直立。","meaning_poem":"峥嵘香号自成器,前程不靠祖业庇。历事早成显峥嵘,松竹影里小蝉倪。立志不愁深涉险,般般自力皆相宜。","image_path":".protected_data/processed/右平齐式/2.png","features":{"left_candle":{"height":"高","ash":"直立"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":2},{"id":"右平齐式-3","name":"福禄香","category":"右平齐式","style_description":"右炷香灰左弯,其余直立。","meaning_poem":"福禄香号心自安,禄计千种福自然。善念与天相契合,无灾无害是前缘。凤阁龙楼人共望,春去还有秋月园。","image_path":".protected_data/processed/右平齐式/3.png","features":{"left_candle":{"height":"高","ash":"直立"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":3},{"id":"右平齐式-4","name":"天库香","category":"右平齐式","style_description":"左炷香灰右弯,其余直立。","meaning_poem":"天库香号自天然,一切随缘自安然。纷纷祖计先忧损,虽有留连岂值钱。不妨再撑钓鱼船,必有鲤鱼上鱼竿。","image_path":".protected_data/processed/右平齐式/4.png","features":{"left_candle":{"height":"高","ash":"右弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":4},{"id":"右平齐式-5","name":"兴师香","category":"右平齐式","style_description":"右炷香灰直立,其余左弯。","meaning_poem":"兴师香号主起兵,兴兵讨伐问罪名。平息暴乱安家邦,抵御外侵定藩屏。倘然不为国家事,兴师动众定为吗。","image_path":".protected_data/processed/右平齐式/5.png","features":{"left_candle":{"height":"高","ash":"左弯"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":5},{"id":"右平齐式-6","name":"流亡香","category":"右平齐式","style_description":"左炷香灰直立,其余右弯。","meaning_poem":"流亡香号避灾祸,离开家乡或祖国。倘然不是流亡者,定是移居求生活。借问何处安此身,香灰五行看生克。","image_path":".protected_data/processed/右平齐式/6.png","features":{"left_candle":{"height":"高","ash":"直立"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":6},{"id":"右平齐式-7","name":"消灾香","category":"右平齐式","style_description":"左炷香灰直立,其余左弯。","meaning_poem":"消灾香号主顺吉,\n恩禄天然不用疑。\n难满灾消时运转,\n百福并臻事可期。\n若然从前风光好,\n春来驾侣更相宜。","image_path":".protected_data/processed/右平齐式/7.png","features":{"left_candle":{"height":"高","ash":"直立"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":7},{"id":"右平齐式-8","name":"脱难香","category":"右平齐式","style_description":"右炷香灰直立,其余右弯。","meaning_poem":"脱难香号消灾难,\n患难之中得救援。\n莫怨疏亲不长久,\n施恩必遇一高贤。\n玉饭金羹好消息,\n终信残年正好闲。","image_path":".protected_data/processed/右平齐式/8.png","features":{"left_candle":{"height":"高","ash":"右弯"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":8},{"id":"右平齐式-9","name":"开劫香","category":"右平齐式","style_description":"左炷香灰直立,其余内弯。","meaning_poem":"开劫香号事难求,一切磨难自此休。春来乍喜花初放,美酒如醉已深秋。财不聚时空费力,劫数尽时财来就。","image_path":".protected_data/processed/右平齐式/9.png","features":{"left_candle":{"height":"高","ash":"直立"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":9},{"id":"右平齐式-10","name":"拜忏香","category":"右平齐式","style_description":"左炷香灰直立,其余内弯。","meaning_poem":"拜忏香号主忏悔,歧路知迷是回归。念经礼拜持大悲,消业免灾喜乐随。善信诵经念佛人,麾节流芳及后辈。","image_path":".protected_data/processed/右平齐式/10.png","features":{"left_candle":{"height":"高","ash":"直立"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":10},{"id":"右平齐式-11","name":"天音香","category":"右平齐式","style_description":"右炷香灰直立,其余外弯。","meaning_poem":"天吝香号主吝啬,爱财如命不肯舍。亲恩求助枉推拖,缠金骑鹤足冷漠。不信道义价千金,不料自己翻了车。","image_path":".protected_data/processed/右平齐式/11.png","features":{"left_candle":{"height":"高","ash":"外弯"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"平","ash":"直立"}},"index":11},{"id":"右平齐式-12","name":"天奢香","category":"右平齐式","style_description":"左炷香灰直立,其余外弯。","meaning_poem":"天奢香号主虚夸,水中明月镜中花。男子奢侈爱排场,女子妖冶喜奢华。来来往往是虚名,忙忙碌碌是虚发。","image_path":".protected_data/processed/右平齐式/12.png","features":{"left_candle":{"height":"高","ash":"直立"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":12},{"id":"右平齐式-13","name":"消业香","category":"右平齐式","style_description":"中炷香灰直立,其余外弯。","meaning_poem":"消业香号如云拢,\n疑是善知障碍重。\n妻若难为夫若病,\n子多不秀宛如空。\n知了忏悔积善行,\n还了业债自从容。","image_path":".protected_data/processed/右平齐式/13.png","features":{"left_candle":{"height":"高","ash":"外弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"外弯"}},"index":13},{"id":"右平齐式-14","name":"威名香","category":"右平齐式","style_description":"中炷香灰直立,其余内弯。","meaning_poem":"威名香号主威慑,\n善知必是能为者。\n或是力量而超人,\n或是武功而绝卓。\n众口皆碑人钦敬,\n威名闻者皆咋舌。","image_path":".protected_data/processed/右平齐式/14.png","features":{"left_candle":{"height":"高","ash":"内弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"内弯"}},"index":14},{"id":"右平齐式-15","name":"勉过香","category":"右平齐式","style_description":"中炷香灰左弯,其余直立。","meaning_poem":"勉过香号破笑颜,原来不在醉里眠。偷香枉学蝶回还,结子不如花开幔。善知无过何必嫌,可信当年多危险。","image_path":".protected_data/processed/右平齐式/15.png","features":{"left_candle":{"height":"高","ash":"直立"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":15},{"id":"右平齐式-16","name":"脱身香","category":"右平齐式","style_description":"中炷香灰右弯,其余直立。","meaning_poem":"脱身香号主摆脱,轻爽自如自欢乐。自古人生否则通,清闲皆由烦恼得。祝尔离得事纠葛,更喜待马上高坡。","image_path":".protected_data/processed/右平齐式/16.png","features":{"left_candle":{"height":"高","ash":"直立"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":16},{"id":"右平齐式-17","name":"投奔香","category":"右平齐式","style_description":"中炷香灰直立,其余左弯。","meaning_poem":"投奔香号寻靠山,\n小鸟依人解忧难。\n若问投奔亲戚好,\n还是朋友能助缘。\n左亲右友看侧香,\n香火暗者莫近前。","image_path":".protected_data/processed/右平齐式/17.png","features":{"left_candle":{"height":"高","ash":"左弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":17},{"id":"右平齐式-18","name":"天幸香","category":"右平齐式","style_description":"中炷香灰直立,其余右弯。","meaning_poem":"天幸香号主荣幸,\n原来命贵比如金。\n娇纵偏爱为儿女,\n朝中衙内受宠幸。\n更许伶俐人缘好,\n天赋资才任尔行。","image_path":".protected_data/processed/右平齐式/18.png","features":{"left_candle":{"height":"高","ash":"右弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":18},{"id":"右平齐式-19","name":"归附香","category":"右平齐式","style_description":"左炷香灰左弯,其余右弯。","meaning_poem":"归附香号主投城,\n缴械投降重归正。\n倘然无关军械事,\n归顺依附息纷争。\n若然问起家中事,\n亦如归顺类相同。","image_path":".protected_data/processed/右平齐式/19.png","features":{"left_candle":{"height":"高","ash":"左弯"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":19},{"id":"右平齐式-20","name":"纳贿香","category":"右平齐式","style_description":"右炷香灰右弯,其余左弯。","meaning_poem":"纳贿香号主贿赂,\n有求于人觅出路。\n借问用钱是用物,\n是多是少怎支付。\n当知行贿和受贿,\n人厌人烦谁自主。","image_path":".protected_data/processed/右平齐式/20.png","features":{"left_candle":{"height":"高","ash":"左弯"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":20},{"id":"右平齐式-21","name":"天柱香","category":"右平齐式","style_description":"左炷香灰右弯,其余内弯。","meaning_poem":"天柱香号主依傍,\n穷困已极无人帮。\n妻宫力薄六亲疏,\n历尽艰辛苦奔忙。\n待问何时适从容,\n坚心自力既希望。","image_path":".protected_data/processed/右平齐式/21.png","features":{"left_candle":{"height":"高","ash":"右弯"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":21},{"id":"右平齐式-22","name":"成材香","category":"右平齐式","style_description":"右炷香灰左弯,其余内弯。","meaning_poem":"成材香号主功名,\n有如日出见光明。\n励精图治感天地,\n甘甜不负苦修行。\n求知学艺终成就,\n振业何须榜上名。","image_path":".protected_data/processed/右平齐式/22.png","features":{"left_candle":{"height":"高","ash":"内弯"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":22},{"id":"右平齐式-23","name":"天医香","category":"右平齐式","style_description":"右炷香灰左弯,其余外弯。","meaning_poem":"天医香号主大吉,病患灾疾遇名医。膏汤丸散方中药,针灸刮刺绝中技。虽然不能挥手去,妙手回春指日期。","image_path":".protected_data/processed/右平齐式/23.png","features":{"left_candle":{"height":"高","ash":"外弯"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":23},{"id":"右平齐式-24","name":"天福香","category":"右平齐式","style_description":"左炷香灰右弯,其余外弯。","meaning_poem":"天福香号福无量,老运亨通福寿长。作事辛勤非为苦,好行善事终报偿。若问儿女家中喜,不必区区说短长。","image_path":".protected_data/processed/右平齐式/24.png","features":{"left_candle":{"height":"高","ash":"右弯"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":24},{"id":"右平齐式-25","name":"祈求香","category":"右平齐式","style_description":"三炷香灰左弯。","meaning_poem":"祈求香号有所求,向神默告莫存留。天知地知你也知,不必一一道根由。若知所求应与否,香灰正反看左右。","image_path":".protected_data/processed/右平齐式/25.png","features":{"left_candle":{"height":"高","ash":"左弯"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":25},{"id":"右平齐式-26","name":"转运香","category":"右平齐式","style_description":"三炷香灰右弯。","meaning_poem":"转运香号好运来,转危为安喜开怀。从今自有大转折,不须埋怨想不开。亲情朋友重续旧,借问残花蜂蝶来。","image_path":".protected_data/processed/右平齐式/26.png","features":{"left_candle":{"height":"高","ash":"右弯"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":26},{"id":"右平齐式-27","name":"增寿香","category":"右平齐式","style_description":"左炷香灰直立,其余搭桥。","meaning_poem":"增寿香号寿龄高,天女麻姑献寿桃。孝悌儿女常相伴,人在玉堂乐陶陶。但怕香火黑烟起,喜庆之余琐碎到。","image_path":".protected_data/processed/右平齐式/27.png","features":{"left_candle":{"height":"高","ash":"直立"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":27},{"id":"右平齐式-28","name":"减岁香","category":"右平齐式","style_description":"右炷香灰直立,其余搭桥。","meaning_poem":"减岁香号有说道,好人好报当知晓。善知自省往日过,孝子善人无寿天。不怕见得此香号,但怕不信因果报。","image_path":".protected_data/processed/右平齐式/28.png","features":{"left_candle":{"height":"高","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"直立"}},"index":28},{"id":"右平齐式-29","name":"天威香","category":"右平齐式","style_description":"左炷香灰左弯,其余搭桥。","meaning_poem":"天威香号抖金盔,手持帅印腰剑配。谁信今朝麾节下,兵随印转在重威。倘若不问军中将,人事逢时尽可为。","image_path":".protected_data/processed/右平齐式/29.png","features":{"left_candle":{"height":"高","ash":"左弯"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":29},{"id":"右平齐式-30","name":"天败香","category":"右平齐式","style_description":"右炷香灰右弯,其余搭桥。","meaning_poem":"天败香号主衰败,倾覆之处天所怪。竭力营谋财散尽,俯仰奋身财不来。劝尔寺庙去朝拜,清心消业时不待。","image_path":".protected_data/processed/右平齐式/30.png","features":{"left_candle":{"height":"高","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"右弯"}},"index":30},{"id":"右平齐式-31","name":"天赐香","category":"右平齐式","style_description":"左炷香灰右弯,其余搭桥。","meaning_poem":"天赐香号沐天恩,\n贵禄两重喜临身。\n天赐麒麟兴大业,\n扶持直上跃龙门。\n彩门久待来奇玉,\n门庭荣旺岁月深。","image_path":".protected_data/processed/右平齐式/31.png","features":{"left_candle":{"height":"高","ash":"右弯"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":31},{"id":"右平齐式-32","name":"天蛰香","category":"右平齐式","style_description":"右炷香灰左弯,其余搭桥。","meaning_poem":"天蛰香号主被动,\n犹如动物冬眠中。\n蛰居潜伏不露面,\n寒鱼依草过隆冬。\n若问有望出头日,\n日暖惊蛰又从容。","image_path":".protected_data/processed/右平齐式/32.png","features":{"left_candle":{"height":"高","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"左弯"}},"index":32},{"id":"右平齐式-33","name":"幸运香","category":"右平齐式","style_description":"三炷香灰搭桥。","meaning_poem":"幸运香号真高兴,身处困境得宠幸。寄人篱下正囫囵,时来运转梦中惊。女人受宠得厚待,男儿升任又添薪。","image_path":".protected_data/processed/右平齐式/33.png","features":{"left_candle":{"height":"高","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":33},{"id":"右平齐式-34","name":"天辅香","category":"右平齐式","style_description":"三炷香灰直立。","meaning_poem":"天辅香号借天力,一双伴侣销金玉。腾身直到凤凰池,月照梅花正得意。终究运逢花似锦,前程自有人依庇。","image_path":".protected_data/processed/右平齐式/34.png","features":{"left_candle":{"height":"高","ash":"直立"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":34},{"id":"右低式-1","name":"凤鸾香","category":"右低式","style_description":"三炷香灰搭桥。","meaning_poem":"凤鸾香号主和美,鸾凤和鸣喜乐随。堪叹夫妇好联手,夫唱妇随和为贵。若问前途经营事,全仗贤妻善主内。","image_path":".protected_data/processed/右低式/1.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":1},{"id":"右低式-2","name":"朗照香","category":"右低式","style_description":"三炷香灰直立。","meaning_poem":"朗照香号透银光,三星照户降吉祥。善知朝暮奉慈善,操守坚洁富贵长。若问黄花蜂蝶事,仙人说尔早主张。","image_path":".protected_data/processed/右低式/2.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"直立"}},"index":2},{"id":"右低式-3","name":"离异香","category":"右低式","style_description":"左炷香灰右弯,其余搭桥。","meaning_poem":"离异香号主离别,儿女亲情或夫妻。方摆鸳鸯同戏水,岂朝一只早分离。儿女提防离别哭,雁鸿飞渡远山急。","image_path":".protected_data/processed/右低式/3.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":3},{"id":"右低式-4","name":"远客香","category":"右低式","style_description":"右炷香灰左弯,其余搭桥。","meaning_poem":"远客香号客人来,七日客来千里外。早备佳馔和菜肴,客人来了好招待。倘若无有远客至,必有近客送浮财。","image_path":".protected_data/processed/右低式/4.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"低","ash":"左弯"}},"index":4},{"id":"右低式-5","name":"背约香","category":"右低式","style_description":"左炷香灰左弯,其余搭桥。","meaning_poem":"背约香号主违约,\n背信弃义事做绝。\n莫怨自己太单纯,\n我枉功夫踏破鞋。\n倘若不贪蝇头利,\n何来骗子弄这些。","image_path":".protected_data/processed/右低式/5.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":5},{"id":"右低式-6","name":"恩爱香","category":"右低式","style_description":"右炷香灰右弯,其余搭桥。","meaning_poem":"恩爱香号主默契,\n岁寒人事两相依。\n鸳鸯花下不须猜。\n帘笼深销正亲昵。\n春尽花残子犹在,\n楹钱花蕊又艳丽。","image_path":".protected_data/processed/右低式/6.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"低","ash":"右弯"}},"index":6},{"id":"右低式-7","name":"天沧香","category":"右低式","style_description":"左炷香灰直立,其余搭桥。","meaning_poem":"天诠香号神明在,\n威严庄重坐金台。\n尔心天地人神知,\n一句良言记心怀。\n行之不义必自毙,\n穷奢极欲必自败。","image_path":".protected_data/processed/右低式/7.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":7},{"id":"右低式-8","name":"和睦香","category":"右低式","style_description":"右炷香灰直立,其余搭桥。","meaning_poem":"和睦香号主和善,\n和和平平而相安。\n婆媳夫妻感情好,\n妯娌之间无嗔怨。\n和谐气氛由何来,\n亏得贤良女婵娟。","image_path":".protected_data/processed/右低式/8.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"低","ash":"直立"}},"index":8},{"id":"右低式-9","name":"乖戾香","category":"右低式","style_description":"三炷香灰右弯。","meaning_poem":"乖戾香号主乖张,家中有人气昂昂。任尔容忍善谦让,百般无奈惹惆怅。易喜易嗔常相伴,苦了冤家好心肠。","image_path":".protected_data/processed/右低式/9.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":9},{"id":"右低式-10","name":"幸运香","category":"右低式","style_description":"三炷香灰右弯。","meaning_poem":"幸运香号好运气,出门见喜堪称奇。彩票竞技人聚处,信马由缰偏得利。一见钟情巧相遇,天降人事好消息。","image_path":".protected_data/processed/右低式/10.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":10},{"id":"右低式-11","name":"悖逆香","category":"右低式","style_description":"右炷香灰左弯,其余外弯。","meaning_poem":"悖逆香号主犯上,小人做事太乖张。从前谄曲会通融,得势无情胜虎狼。此人不在官衙内,悖逆悖出败家郎。","image_path":".protected_data/processed/右低式/11.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"低","ash":"左弯"}},"index":11},{"id":"右低式-12","name":"姻缘香","category":"右低式","style_description":"左炷香灰右弯,其余外弯。","meaning_poem":"姻缘香号主良缘,夜静风清月儿圆。高山流水拨古筝,一曲龙吟起波澜。若说缘分长与短,旦看香灰五行断。","image_path":".protected_data/processed/右低式/12.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"低","ash":"外弯"}},"index":12},{"id":"右低式-13","name":"天宝香","category":"右低式","style_description":"左炷香灰右弯,其余内弯。","meaning_poem":"天宝香号吉星照,\n好运临头厄运消。\n以前花开雨打花,\n狼藉春风折嫩梢。\n往后得遇荣华禄,\n掘井开池得珠宝。","image_path":".protected_data/processed/右低式/13.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"低","ash":"内弯"}},"index":13},{"id":"右低式-14","name":"和合香","category":"右低式","style_description":"右炷香灰左弯,其余内弯。","meaning_poem":"和合香号主善缘,\n恰似云开月再圆。\n兄弟之缘雪中炭,\n股肱之力春风暖。\n往日衔怨惊梦觉,\n世情皆好合就然。","image_path":".protected_data/processed/右低式/14.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"低","ash":"左弯"}},"index":14},{"id":"右低式-15","name":"得意香","category":"右低式","style_description":"左炷香灰左弯,其余右弯。","meaning_poem":"得意香号主顺遂,\n日照桑榆有光辉。\n因人借力有恩遇,\n天赐功勋弄金微。\n天廪陈仓足有余,\n两重荣耀两重贵。","image_path":".protected_data/processed/右低式/15.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":15},{"id":"右低式-16","name":"悖晦香","category":"右低式","style_description":"右炷香灰右弯,其余左弯。","meaning_poem":"悖晦香号主糊涂,\n立事无根难做主。\n大宽小急多颠倒,\n紧慢不匀错常出。\n忘前失后长街上,\n小心遗失钱和物。","image_path":".protected_data/processed/右低式/16.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":16},{"id":"右低式-17","name":"春试香","category":"右低式","style_description":"中炷香灰直立,其余左弯。","meaning_poem":"春试香号主科考,平生立事好营造。纵然不是王家禄,也是刘郎身价高。若然不求名利事,春郊试马花争俏。","image_path":".protected_data/processed/右低式/17.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"左弯"}},"index":17},{"id":"右低式-18","name":"艳福香","category":"右低式","style_description":"中炷香灰直立,其余右弯。","meaning_poem":"艳福香号桃花累,无意拈花花自随。无情鸿雁多分散,有意鸳鸯不肯飞。只愁红蕊风零落。山高水远无路归。","image_path":".protected_data/processed/右低式/18.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"右弯"}},"index":18},{"id":"右低式-19","name":"利禄香","category":"右低式","style_description":"中炷香灰左弯,其余直立。","meaning_poem":"利禄香号堪自豪。利禄悠然志气高。莫怪程途来往走,晚来孤路自逍遥。若问善知家何在,重开孤竹钓金鳖。","image_path":".protected_data/processed/右低式/19.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"低","ash":"直立"}},"index":19},{"id":"右低式-20","name":"天厨香","category":"右低式","style_description":"中炷香灰右弯,其余直立。","meaning_poem":"天厨香号话香主,满腰金银当知足。米积陈仓食有余,半供鼠耗半供厨。回首旧人奈何事,如何平地楚天舒。","image_path":".protected_data/processed/右低式/20.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"低","ash":"直立"}},"index":20},{"id":"右低式-21","name":"登科香","category":"右低式","style_description":"左炷香灰直立,其余外弯。","meaning_poem":"登科香号主声名,\n金钟出冶晌叮铃。\n几年驻足望仙家,\n回首黄昏月满庭。\n逢时应遂晚年心,\n少小清华鬼神惊。","image_path":".protected_data/processed/右低式/21.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"低","ash":"外弯"}},"index":21},{"id":"右低式-22","name":"天瑾香","category":"右低式","style_description":"中炷香灰直立,其余内弯。","meaning_poem":"天瑾香号主贞洁,\n宛如荷花无泥榭。\n知音多近自操守,\n傍花依玉心无邪。\n莫言娇俏黄花女,\n子然鳏寡不赎衷。","image_path":".protected_data/processed/右低式/22.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"内弯"}},"index":22},{"id":"右低式-23","name":"彩头香","category":"右低式","style_description":"右炷香灰直立,其余外弯。","meaning_poem":"彩头香号好预兆,掘地见金出意料。不是彩球怀中抱,便是抽头中彩票。求利获利知音遇,变更世事生涯好。","image_path":".protected_data/processed/右低式/23.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"低","ash":"直立"}},"index":23},{"id":"右低式-24","name":"天破香","category":"右低式","style_description":"左炷香灰直立,其余外弯。","meaning_poem":"天破香号主破财,生来磨难多败财。祖基旧处身难靠,一生鸳鸯两分开。倘然今日无征兆,五年之后尔再来。","image_path":".protected_data/processed/右低式/24.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"低","ash":"外弯"}},"index":24},{"id":"右低式-25","name":"妻财香","category":"右低式","style_description":"左炷香灰直立,其余内弯。","meaning_poem":"妻财香号主偏财,见财见喜妻带来。不信命里妻宫在,百样亲情皆是债。早寻风月为知己,免学秋来张郎哀。","image_path":".protected_data/processed/右低式/25.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"低","ash":"内弯"}},"index":25},{"id":"右低式-26","name":"和容香","category":"右低式","style_description":"右炷香灰直立,其余内弯。","meaning_poem":"和容香号主融融,家庭和睦乐其中。若问前程儿女事,和容兴家自繁荣。无心倚玉足徜徉,梅蕊蔼破晚香浓。","image_path":".protected_data/processed/右低式/26.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"低","ash":"直立"}},"index":26},{"id":"右低式-27","name":"大徽香","category":"右低式","style_description":"左炷香灰直立,其余左弯。","meaning_poem":"天徽香号主征用,征税征粮或征兵。倘然重税来搜刮。谨依国法莫乱行。土地房屋若征用,体念国情莫争竞。","image_path":".protected_data/processed/右低式/27.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"低","ash":"左弯"}},"index":27},{"id":"右低式-28","name":"盘仓香","category":"右低式","style_description":"右炷香灰直立,其余右弯。","meaning_poem":"盘仓香号鼠盘仓,子鼠盘仓广积粮。临渴掘井为时晚,居安思危好主张。倘问进退安身处,手中有粮心不慌。","image_path":".protected_data/processed/右低式/28.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"低","ash":"直立"}},"index":28},{"id":"右低式-29","name":"天蚩香","category":"右低式","style_description":"右炷香灰直立,其余左弯。","meaning_poem":"天蚩香号笑你痴,怜儿爱女反求疵。都说多儿多福乐,不信残烛暮年时。分明儿大不由娘,何必沉吟作陈词。","image_path":".protected_data/processed/右低式/29.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"低","ash":"直立"}},"index":29},{"id":"右低式-30","name":"文曲香","category":"右低式","style_description":"左炷香灰直立,其余右弯。","meaning_poem":"文曲香号透粼光,文章文艺尽流芳。若然文职在朝廷,一代文宗振家邦。假若文童或书生,文才文凭双金章。","image_path":".protected_data/processed/右低式/30.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":30},{"id":"右低式-31","name":"增福香","category":"右低式","style_description":"右炷香灰左弯,其余直立。","meaning_poem":"增福香号主升平,\n满门鸿福老寿星。\n躬行慈善多喜乐,\n十日之内添人丁。\n不添人口亦如意,\n闲情雅致自安宁。","image_path":".protected_data/processed/右低式/31.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"左弯"}},"index":31},{"id":"右低式-32","name":"恭喜香","category":"右低式","style_description":"左炷香灰右弯.其余直立。","meaning_poem":"恭喜香号传佳信,\n老树枝头喜鹊鸣。\n成对鸳鸯游碧水,\n晚来一双更逸情。\n古树春风长嫩枝,\n故园夜雨芳草新。","image_path":".protected_data/processed/右低式/32.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"直立"}},"index":32},{"id":"右低式-33","name":"迎春香","category":"右低式","style_description":"左炷香灰左弯,其余直立。","meaning_poem":"迎春香号喜迎春,萧条枯木沐春风。莺燕满林春色好,鸳鸯对对碧波深。莫怨唯尔更变迟,宜静待时看春分。","image_path":".protected_data/processed/右低式/33.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"直立"}},"index":33},{"id":"右低式-34","name":"抑郁香","category":"右低式","style_description":"右炷香灰右弯,其余直立。","meaning_poem":"抑郁香号含愤恨,不能诉说心烦闷。自恨平生未称心,暗地拾襟拭泪痕。不如收拾青蛙起,走入云中换家门。","image_path":".protected_data/processed/右低式/34.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"右弯"}},"index":34},{"id":"中高式-1","name":"小天真香","category":"中高式","style_description":"左炷香灰左弯,其余直立。","meaning_poem":"小天真香透天宫,引领群仙齐出洞。落下云头坐金台,无言自在尔心中。若问前程儿女事,天开紫府尽春风。","image_path":".protected_data/processed/中高式/1.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":1},{"id":"中高式-2","name":"天毒香","category":"中高式","style_description":"右炷香灰右弯,其余直立。","meaning_poem":"天毒香号小人坏,暗中图谋来伤害。堪叹善知性耿直,求实办事太坦率。接人待物当留心,防患未然则无碍。","image_path":".protected_data/processed/中高式/2.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":2},{"id":"中高式-3","name":"烦难香","category":"中高式","style_description":"右炷香灰左弯,其余直立。","meaning_poem":"烦难香号惹心烦,\n喜怒无常多抱怨。\n千般忧虑心中有,\n百样营求却一般。\n若要身心随意处,\n秋令菊黄月自圆。","image_path":".protected_data/processed/中高式/3.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":3},{"id":"中高式-4","name":"变革香","category":"中高式","style_description":"左炷香灰右弯,其余直立。","meaning_poem":"变革香号主改良,\n兴办革除好主张。\n但得朝廷得恩宠,\n有朝一日成栋梁。\n倘然若问事究竟,\n香灰五行辩作向。","image_path":".protected_data/processed/中高式/4.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":4},{"id":"中高式-5","name":"劳碌香","category":"中高式","style_description":"右炷香灰直立,其余左弯。","meaning_poem":"劳碌香号多辛苦,一世奔波不自如。惟有草堂鸥鹭盛,青松翠柏伴苦竹。休说平生未得福,殷实人家亦知足。","image_path":".protected_data/processed/中高式/5.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":5},{"id":"中高式-6","name":"天权香","category":"中高式","style_description":"左炷香灰直立,其余右弯。","meaning_poem":"天权香号主专权,大权独揽手遮天。倘然不是在朝廷,居家一人说了算。旦怕强使夫惧内,戏水鸳鸯终有散。","image_path":".protected_data/processed/中高式/6.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":6},{"id":"中高式-7","name":"蜃景香","category":"中高式","style_description":"左炷香灰直立,其余左弯。","meaning_poem":"蜃景香号主虚空,\n海市蜃楼云雾中。\n生来休怨未从容,\n沙里淘金莫算工。\n待得不记南柯梦,\n吆牛亲耕伴春风。","image_path":".protected_data/processed/中高式/7.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":7},{"id":"中高式-8","name":"天庆香","category":"中高式","style_description":"右炷香灰直立,其余右弯。","meaning_poem":"天庆香号主庆祝,\n众人打起胜利鼓。\n祝贺征伐得胜归,\n祝贺大业展宏图。\n无论善知为哪桩,\n都是成功耀先祖。","image_path":".protected_data/processed/中高式/8.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":8},{"id":"中高式-9","name":"天策香","category":"中高式","style_description":"左炷香灰直立,其余内弯。","meaning_poem":"天策香号主周到,\n计出万全最重要。\n善知图谋举大事,\n可望锦枝结妖桃。\n不论婚丧嫁娶事,\n周到周到尽周到。","image_path":".protected_data/processed/中高式/9.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":9},{"id":"中高式-10","name":"天驹香","category":"中高式","style_description":"右炷香灰直立,其余内弯。","meaning_poem":"天驹香号大有为,\n成败只因明是非。\n几多梅插架前书,\n日暮桑榆不用悲。\n终身远近多翻覆,\n英雄壮志终须遂。","image_path":".protected_data/processed/中高式/10.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"平","ash":"直立"}},"index":10},{"id":"中高式-11","name":"天淹香","category":"中高式","style_description":"右炷香灰直立,其余外弯。","meaning_poem":"天淹香号主埋没,洪水滔滔漫高坡。若问举家度日事,多因前事啜泣过。不得器重暗伤感,妨忌偏爱心窝火。","image_path":".protected_data/processed/中高式/11.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"平","ash":"直立"}},"index":11},{"id":"中高式-12","name":"天孤香","category":"中高式","style_description":"左炷香灰直立,其余外弯。","meaning_poem":"天孤香号孤零零,孤军驻扎硬屯兵。力倦心疲战不成,一鼓瑶琴弦断音。若问家事儿女事,六亲眷属冷若冰。","image_path":".protected_data/processed/中高式/12.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":12},{"id":"中高式-13","name":"芝兰香","category":"中高式","style_description":"中炷香灰直立,其余外弯。","meaning_poem":"芝兰香号好运交,恰似芝兰偃蓬蒿。芝兰弄草人称瑞,月到中天影更高。生平莫道多蹉跎,自此门前祥光照。","image_path":".protected_data/processed/中高式/13.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"外弯"}},"index":13},{"id":"中高式-14","name":"麒麟香","category":"中高式","style_description":"中炷香灰直立,其余内弯。","meaning_poem":"麒麟香号主荣贵,麒麟送玉生光辉。莫言身荣近皇家。有志四方皆有为。谁信今朝门庭旺,小家碧玉也举杯。","image_path":".protected_data/processed/中高式/14.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"内弯"}},"index":14},{"id":"中高式-15","name":"妆奁香","category":"中高式","style_description":"中炷香灰左弯,其余直立。","meaning_poem":"妆奁香号说嫁妆,\n新婚所用备置忙。\n谁知笑里有分张,嫁妆多少费商量。\n直饶宽缓道相宜,切莫贪嗔讲排场。","image_path":".protected_data/processed/中高式/15.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":15},{"id":"中高式-16","name":"天英香","category":"中高式","style_description":"中炷香灰右弯,其余直立。","meaning_poem":"天英香号主归来,\n胜利荣归喜开怀。\n回首几回进步难,\n惜别乡井身在外。\n幸有一枝梅绽萼,\n谁信当年梅正开。","image_path":".protected_data/processed/中高式/16.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":16},{"id":"中高式-17","name":"口舌香","category":"中高式","style_description":"中炷香灰直立,其余左弯。","meaning_poem":"口舌香号是非多,\n七日之内难脱过。\n心直口快惹怨恨,\n好心弄事反成拙。\n家人不吵旁人找,\n平地风波动干戈。","image_path":".protected_data/processed/中高式/17.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":17},{"id":"中高式-18","name":"天才香","category":"中高式","style_description":"中炷香灰直立,其余右弯。","meaning_poem":"天才香号天禀才,\n休嗟不遇空怀才。\n分定皆因运未至,\n试看如今鸿运来。\n天生我才必有用,\n智慧艺术本是财。","image_path":".protected_data/processed/中高式/18.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":18},{"id":"中高式-19","name":"喜庆香","category":"中高式","style_description":"左炷香灰左弯,其余右弯。","meaning_poem":"喜庆香号多喜乐,\n三日之内喜事多。\n不是梧桐招凤凰,\n便是黄花果蒂落。\n借问夕阳何景色,\n鸳慵鸯懒正和合。","image_path":".protected_data/processed/中高式/19.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":19},{"id":"中高式-20","name":"天赊香","category":"中高式","style_description":"右炷香灰右弯,其余左弯。","meaning_poem":"天赊香号主赊欠,\n钱财往来生嗔怨。\n赊购赊销或赊账,\n回头货款结算难。\n试问何时能清还,\n香灰作向五行堪。","image_path":".protected_data/processed/中高式/20.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":20},{"id":"中高式-21","name":"增财香","category":"中高式","style_description":"左炷香灰右弯。其余内弯。","meaning_poem":"增财香号报佳音,\n好似双手抱金银。\n时来暮去春已深,\n休说前事背时人。\n十日之内必进益,\n不见财禄见新人。","image_path":".protected_data/processed/中高式/21.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":21},{"id":"中高式-22","name":"天役香","category":"中高式","style_description":"右炷香灰左弯,其余内弯。","meaning_poem":"天役香号主奴役,\n强使牲畜或人力。\n欲上市井买牲畜,\n雇人雇请皆由你。\n倘若为人坐杂役,\n仆人婢女亦相宜。","image_path":".protected_data/processed/中高式/22.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":22},{"id":"中高式-23","name":"天吉香","category":"中高式","style_description":"右炷香灰左弯,其余外弯。","meaning_poem":"天吉香号显才能,毛遂自荐古今颂。天赋天机重相遇,脱颖而出展雄风。可贺事业和功名,天赐功勋此年中。","image_path":".protected_data/processed/中高式/23.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":23},{"id":"中高式-24","name":"玄风香","category":"中高式","style_description":"左炷香灰右弯,其余外弯。","meaning_poem":"玄风香号乃嘉懿,更在善知悟玄机。几年逐浪随波过,莫叹到老身孤立。贵人只在坤离位,引你同登步天梯。","image_path":".protected_data/processed/中高式/24.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":24},{"id":"中高式-25","name":"盗贼香","category":"中高式","style_description":"三炷香灰左弯。","meaning_poem":"盗贼香号须小心,恐有贼寇来剪径。人来投我我投人,知人知面不知心。乾坤夕惕不为怪,劫匪绺窃不容情。","image_path":".protected_data/processed/中高式/25.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":25},{"id":"中高式-26","name":"遂心香","category":"中高式","style_description":"三炷香灰右弯。","meaning_poem":"遂心香号合心意,般般件件皆相宜。一对鸳鸯同戏水,一行垂柳绕河堤。更看晚来一果鲜,无聊悉听子规啼。","image_path":".protected_data/processed/中高式/26.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":26},{"id":"中高式-27","name":"天喜香","category":"中高式","style_description":"左炷香灰直立,其余搭桥。","meaning_poem":"天喜香号送贺礼,男婚女嫁皆欢喜。尤女出嫁亲友来,送礼添箱送情谊。倘若不言婚嫁事,家中必有人送礼。","image_path":".protected_data/processed/中高式/27.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":27},{"id":"中高式-28","name":"天枭香","category":"中高式","style_description":"右炷香灰直立,其余搭桥。","meaning_poem":"天枭香号主枉法,盐枭私贩寄生涯。纵然不是走私事,偷税漏税避检查。欲知如是祸是福,此心不动是安家。","image_path":".protected_data/processed/中高式/28.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"直立"}},"index":28},{"id":"中高式-29","name":"天狼香","category":"中高式","style_description":"左炷香灰左弯,其余搭桥。","meaning_poem":"天狼香号主贪赃,徇私舞弊巧隐藏。莫说不是官场人,为富不仁坏心肠。若问前程往后事,弃旧重新当自强。","image_path":".protected_data/processed/中高式/29.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":29},{"id":"中高式-30","name":"天掩香","category":"中高式","style_description":"右炷香灰右弯,其余搭桥。","meaning_poem":"天掩香号主冒险,\n作伪作弊想赚钱。\n若说钱财得意事,\n只是初时暂相安。\n任尔下人或老板。\n夜半风狂枝叶残。","image_path":".protected_data/processed/中高式/30.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"右弯"}},"index":30},{"id":"中高式-31","name":"登基香","category":"中高式","style_description":"左炷香灰右弯,其余搭桥。","meaning_poem":"登基香号主腾达,\n龙虎座上威天下。\n不是玉龙出深潭,\n便是金凤飞谷峡。\n平民百姓遇此香,\n遇贵相逢必发家。","image_path":".protected_data/processed/中高式/31.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":31},{"id":"中高式-32","name":"暗事香","category":"中高式","style_description":"右炷香灰左弯,其余搭桥。","meaning_poem":"暗事香号不光明。\n装模作样假正经。\n不是背地有积蓄,\n便是暗昧有私情。\n若问此桩道是谁,\n做者心里明如镜。","image_path":".protected_data/processed/中高式/32.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"左弯"}},"index":32},{"id":"中高式-33","name":"天匿香","category":"中高式","style_description":"三炷香灰茯桥。","meaning_poem":"天匿香号主逃匿,躲躲藏藏惨凄凄。劝尔早早梦中醒,须知如此岂有期。国法难容侥幸客,天理昭昭亦不依。","image_path":".protected_data/processed/中高式/33.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":33},{"id":"中高式-34","name":"大天真香","category":"中高式","style_description":"三炷香灰直立。","meaning_poem":"大天真香佛祖到,唯喜善知品格高。积德修真感上天,终遇天真佛光照。绿窗朱户隐菩提,有志不妨钓金鳖。","image_path":".protected_data/processed/中高式/34.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":34},{"id":"中低左参差-1","name":"参商香","category":"中低左参差","style_description":"左炷香灰左弯,其余直立。","meaning_poem":"参商香号主分张,\n夫妻不合若参商。\n情随事迁有谁知,\n情趣不投不想让。\n若问究竟合与分,\n神明岂能乱主张。","image_path":".protected_data/processed/中低左参差/1.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":1},{"id":"中低左参差-2","name":"罢黜香","category":"中低左参差","style_description":"右炷香灰右弯,其余直立。","meaning_poem":"罢黜香号受贬低,\n人如云天落平地。\n渎职贪赃被人欺,\n究竟不如问自己。\n如若不在为官宜,\n时逢背运多不利。","image_path":".protected_data/processed/中低左参差/2.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":2},{"id":"中低左参差-3","name":"包赔香","category":"中低左参差","style_description":"右炷香灰左弯,其余直立。","meaning_poem":"包赔香号主破财。\n赔礼贴钱受责怪。\n谁知身手不由心,\n平地磕绊败兴来。\n当知此过非为过,\n财去人安是当该。","image_path":".protected_data/processed/中低左参差/3.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":3},{"id":"中低左参差-4","name":"退财香","category":"中低左参差","style_description":"左炷香灰右弯,其余直立。","meaning_poem":"退财香号犯退神,\n任尔性巧机谋深。\n作事重重易破财,\n行坐处处难立身。\n个中生意生是非,\n争奈身犹锁关门。","image_path":".protected_data/processed/中低左参差/4.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":4},{"id":"中低左参差-5","name":"给窃香","category":"中低左参差","style_description":"右炷香灰直立,其余左弯。","meaning_poem":"给窃香号报尔知,\n三日之内有盗失。\n不是衣兜被人顺,\n便是意外损失至。\n善知此劫当回避,\n不信由尔试一试。","image_path":".protected_data/processed/中低左参差/5.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"低","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":5},{"id":"中低左参差-6","name":"亏空香","category":"中低左参差","style_description":"左炷香灰直立,其余右弯。","meaning_poem":"亏空香号生意淡,争奈苦辛不赚钱。同样人家贩丝绸,人家赢利我难堪。要知何由财不就,趋之若鹜是弊端。","image_path":".protected_data/processed/中低左参差/6.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"低","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":6},{"id":"中低左参差-7","name":"天魁香","category":"中低左参差","style_description":"左炷香灰直立,其余左弯。","meaning_poem":"天魁香号主荣昌,用意功名别有方。莫嗟孤雁寒江阔,振翼飞渡见山岗。若说洞房花烛事,绕池翠柳笑鸳鸯。","image_path":".protected_data/processed/中低左参差/7.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"低","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":7},{"id":"中低左参差-8","name":"风波香","category":"中低左参差","style_description":"右炷香灰直立,其余右弯。","meaning_poem":"风波香号起纠纷,是非口舌临自身。堪叹一片和平心,语不妄谈反生嗔。原来举用费商量,一个钱字恨怨深。","image_path":".protected_data/processed/中低左参差/8.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"低","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":8},{"id":"中低左参差-9","name":"凶兆香","category":"中低左参差","style_description":"左炷香灰直立,其余内弯。","meaning_poem":"凶兆香号主大凶,\n七日之内灾祸生。\n若要谋求经营客,\n货物进出当慎重。\n目前若有踌躇事,\n只宜延缓先放松。","image_path":".protected_data/processed/中低左参差/9.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"低","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":9},{"id":"中低左参差-10","name":"退赔香","category":"中低左参差","style_description":"右炷香灰直立,其余内弯。","meaning_poem":"退赔香号主赔偿,\n多为侵吞而还偿。\n若问谁是赔偿主,\n仔细看好中炷香。\n香灰作向辨正反,\n是他是我自端详。","image_path":".protected_data/processed/中低左参差/10.png","features":{"left_candle":{"height":"低","ash":"内弯"},"middle_candle":{"height":"低","ash":"内弯"},"right_candle":{"height":"平","ash":"直立"}},"index":10},{"id":"中低左参差-11","name":"天印香","category":"中低左参差","style_description":"右炷香灰直立,其余外弯。","meaning_poem":"天印香号掌金印,逢时应遂晚年心。呼奴唤婢好气派,吆五喝六威风凛。若知兴废前分定,利名都是逐时新。","image_path":".protected_data/processed/中低左参差/11.png","features":{"left_candle":{"height":"低","ash":"外弯"},"middle_candle":{"height":"低","ash":"外弯"},"right_candle":{"height":"平","ash":"直立"}},"index":11},{"id":"中低左参差-12","name":"天愧香","category":"中低左参差","style_description":"左炷香灰直立,其余外弯。","meaning_poem":"天愧香号主愧疚,惭愧不安满腹忧。负债负约或负心,若莫怄气闹别扭。莫说问心亦无愧,何必强词辩根由。","image_path":".protected_data/processed/中低左参差/12.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"低","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":12},{"id":"中低左参差-13","name":"误伤香","category":"中低左参差","style_description":"中炷香灰直立,其余外弯。","meaning_poem":"误伤香号伤无意,\n无意之中偏晦气。\n三日之内有殴斗,\n必有失手伤身体。\n善知遇此当回避,\n万勿逞强好斗争。","image_path":".protected_data/processed/中低左参差/13.png","features":{"left_candle":{"height":"低","ash":"外弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"外弯"}},"index":13},{"id":"中低左参差-14","name":"佛张香","category":"中低左参差","style_description":"中炷香灰直立,其余内弯。","meaning_poem":"俯张香号主欺骗,\n七日之内小人见。\n出门宿住当须防,\n驿站码头莫留连。\n把式玩艺莫贪看,\n大小便宜不可占。","image_path":".protected_data/processed/中低左参差/14.png","features":{"left_candle":{"height":"低","ash":"内弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"内弯"}},"index":14},{"id":"中低左参差-15","name":"报失香","category":"中低左参差","style_description":"中炷香灰左弯,其余直立。","meaning_poem":"报失香号失财务,\n香灰昏暗辨何物。\n中灶金银左衣物,\n右炷畜禽和粮谷。\n若还要问丢何物,\n运卦五行知去路。","image_path":".protected_data/processed/中低左参差/15.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"低","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":15},{"id":"中低左参差-16","name":"走失香","category":"中低左参差","style_description":"中炷香灰右弯,其余直立。","meaning_poem":"走失香号心慌慌,\n人或家畜迷路上。\n若问去路何日归,\n中炷香灰寻作向。\n四方八隅对八卦,\n五行生克断其详。","image_path":".protected_data/processed/中低左参差/16.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"低","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":16},{"id":"中低左参差-17","name":"失窃香","category":"中低左参差","style_description":"中炷香灰直立,其余左弯。","meaning_poem":"失窃香号被人偷,\n伤财惹气堪使忧。\n三日不见七日见,\n鬼使神差贼顺手。\n出门乘车逛店铺,\n家里房门要谨守。","image_path":".protected_data/processed/中低左参差/17.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":17},{"id":"中低左参差-18","name":"失时香","category":"中低左参差","style_description":"中炷香灰直立,其余右弯。","meaning_poem":"失时香号错时机,\n知音不遇空劳力。\n雁过高山翼倦飞,\n且随鸥鹭整羽衣。\n从来做事犯忧疑,\n错过身边好时机。","image_path":".protected_data/processed/中低左参差/18.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":18},{"id":"中低左参差-19","name":"失闪香","category":"中低左参差","style_description":"左炷香灰左弯,其余右弯。","meaning_poem":"失闪香号出意外,一不留神酿成灾。疏忽注意两可间,神差鬼使怪不怪。三日之内必有显,水火跌损差错来。","image_path":".protected_data/processed/中低左参差/19.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"低","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":19},{"id":"中低左参差-20","name":"破费香","category":"中低左参差","style_description":"右炷香灰右弯,其余左弯。","meaning_poem":"破费香号主抛费,钱财时光两虚费。陪酒陪歌空度日,来往人情难推诿。更有一笔要开销,家乡故里要回归。","image_path":".protected_data/processed/中低左参差/20.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"低","ash":"左弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":20},{"id":"中低左参差-21","name":"赔累香","category":"中低左参差","style_description":"左炷香灰右弯,其余内弯。","meaning_poem":"赔累香号做买卖,\n亏了本钱又欠债。\n雁斗西风多冷落,\n鸳恨两岸未相爱。\n几经努力难回天,\n无言终日暗悲哀。","image_path":".protected_data/processed/中低左参差/21.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"低","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":21},{"id":"中低左参差-22","name":"天休香","category":"中低左参差","style_description":"右炷香灰左弯。其余内弯。","meaning_poem":"天休香号主暂歇,\n不是休学便休业。\n因天因病因天时,\n纵然无奈是症结。\n倘问相关前程事,\n移桃栽杏乃俊杰。","image_path":".protected_data/processed/中低左参差/22.png","features":{"left_candle":{"height":"低","ash":"内弯"},"middle_candle":{"height":"低","ash":"内弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":22},{"id":"中低左参差-23","name":"延搁香","category":"中低左参差","style_description":"右炷香灰左弯,其余外弯。","meaning_poem":"延搁香号主耽搁,推三阻四多推拖。延误时日失机缘,无奈借口有其说。借问所求成与否,成事主在事多磨。","image_path":".protected_data/processed/中低左参差/23.png","features":{"left_candle":{"height":"低","ash":"外弯"},"middle_candle":{"height":"低","ash":"外弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":23},{"id":"中低左参差-24","name":"典押香","category":"中低左参差","style_description":"左炷香灰右弯,其余外弯。","meaning_poem":"典押香号主困顿,生计不利见亏损。处境艰危无良策,只好典当解危困。假若君家无窘况,必见人事多不顺。","image_path":".protected_data/processed/中低左参差/24.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"低","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":24},{"id":"中低左参差-25","name":"天镇香","category":"中低左参差","style_description":"三炷香灰左弯。","meaning_poem":"天镇香号镇妖孽,妖魔鬼怪天来灭。坏事小人皆遁去,怪异不祥亦根绝。若说妖言惑众事,自然风平浪已歇。","image_path":".protected_data/processed/中低左参差/25.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"低","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":25},{"id":"中低左参差-26","name":"灾患香","category":"中低左参差","style_description":"三炷香灰右弯。","meaning_poem":"灾患香号有灾殃,荒年荒月闹灾荒。水火来时不留情,地震过后无家乡。此年此月此时中,惟念弥陀灾不降。","image_path":".protected_data/processed/中低左参差/26.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"低","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":26},{"id":"中低左参差-27","name":"天灾香","category":"中低左参差","style_description":"左炷香灰直立,其余搭桥。","meaning_poem":"天灾香号主灾害,水旱风雹地震来。若问究竟什么灾,年干五行仔细排。香灰作向分五行,生克制化知何灾。","image_path":".protected_data/processed/中低左参差/27.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":27},{"id":"中低左参差-28","name":"天火香","category":"中低左参差","style_description":"右炷香灰直立,其余搭桥。","meaning_poem":"天火香号天降灾,灾害出人意料外。风雷电闪击树木,击毁门窗或楼台。引发火源火连片,危及生命与钱财。","image_path":".protected_data/processed/中低左参差/28.png","features":{"left_candle":{"height":"低","ash":"搭桥"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"平","ash":"直立"}},"index":28},{"id":"中低左参差-29","name":"水灾香","category":"中低左参差","style_description":"左炷香灰左弯,其余搭桥。","meaning_poem":"水灾香号水成患,山洪暴发水泛滥。冲毁河堤淹村庄,淹没房屋与良田。倘然不见洪涝害,家中有人遇水难。","image_path":".protected_data/processed/中低左参差/29.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":29},{"id":"中低左参差-30","name":"借贷香","category":"中低左参差","style_description":"右炷香灰右弯,其余搭桥。","meaning_poem":"借贷香号动往来,借物借钱出无奈。若问借贷休与咎,切记不要莫不开。借钱给人要不来,向人借钱难还债。","image_path":".protected_data/processed/中低左参差/30.png","features":{"left_candle":{"height":"低","ash":"搭桥"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"平","ash":"右弯"}},"index":30},{"id":"中低左参差-31","name":"天怨香","category":"中低左参差","style_description":"左炷香灰右弯。其余搭桥。","meaning_poem":"天怨香号主怨恨,人微言轻自屈身。鹊巢鸠占禁不住。动辙得咎口难申。寸肠欲断求安乐,回首胸襟沾泪痕。","image_path":".protected_data/processed/中低左参差/31.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":31},{"id":"中低左参差-32","name":"逆境香","category":"中低左参差","style_description":"右炷香灰左弯,其余搭桥。","meaning_poem":"逆境香号不顺利,事若鞭长不可及。莫叹耕耘无收成,莫说风雨打湿衣。能人多由逆境出。功名却待多坚毅。","image_path":".protected_data/processed/中低左参差/32.png","features":{"left_candle":{"height":"低","ash":"搭桥"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"平","ash":"左弯"}},"index":32},{"id":"中低左参差-33","name":"圆房香","category":"中低左参差","style_description":"三炷香灰搭桥。","meaning_poem":"圆房香号喜中哭,定是婚配不自主。若问鸳鸯偕白头,茭荷正打相思树。倘然不涉婚姻事,举事谋财见亏负。","image_path":".protected_data/processed/中低左参差/33.png","features":{"left_candle":{"height":"低","ash":"搭桥"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":33},{"id":"中低左参差-34","name":"破财香","category":"中低左参差","style_description":"三炷香灰直立。","meaning_poem":"破财香号主伤财,百般用心亦无奈。曾经弄巧翻成拙,每向求安惊梦来。休嗟命里不占财,曲突徙薪笑尔呆。","image_path":".protected_data/processed/中低左参差/34.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":34},{"id":"中高左参差-1","name":"忧愤香","category":"中高左参差","style_description":"左炷香灰左弯,其余直立。","meaning_poem":"忧愤香号主愤慨,几番做事有人坏。每次成功都有破,求财不成反累债。借问报应有没有,三五个月自明白。","image_path":".protected_data/processed/中高左参差/1.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":1},{"id":"中高左参差-2","name":"威胁香","category":"中高左参差","style_description":"右炷香灰右弯,其余直立。","meaning_poem":"威胁香号主堪忧,有人威胁或利诱。旦看自此半月内,或因钱财或因仇。武力逼迫不发生,诱拐诈骗肯定有。","image_path":".protected_data/processed/中高左参差/2.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":2},{"id":"中高左参差-3","name":"招事香","category":"中高左参差","style_description":"右炷香灰左弯,其余直立。","meaning_poem":"招事香号惹人嫌,近有是非生埋怨。本来无有伤人意,多嘴多舌受干连。倘然不是多嘴人,招风招眼生事端。","image_path":".protected_data/processed/中高左参差/3.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":3},{"id":"中高左参差-4","name":"转嫁香","category":"中高左参差","style_description":"左炷香灰右弯,其余直立。","meaning_poem":"转嫁香号主嫁祸,伤天害理损阴德。不是负担不承受,便是罪名要推托。善知小人在背后,劝尔不可不琢磨。","image_path":".protected_data/processed/中高左参差/4.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":4},{"id":"中高左参差-5","name":"天荣香","category":"中高左参差","style_description":"右炷香灰直立,其余左弯。","meaning_poem":"天荣香号主繁荣,家业兴盛乐融融。倘若家中有不顺,那是自己不相容。原来命中早排定,生涯虎口显光荣。","image_path":".protected_data/processed/中高左参差/5.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":5},{"id":"中高左参差-6","name":"繁难香","category":"中高左参差","style_description":"左炷香灰直立,其余右弯。","meaning_poem":"繁难香号主犯难,般般件件难周全。如何施恩招怨恨,烧香反而引祸端。要知个中真缘由,孤高守旧少机缘。","image_path":".protected_data/processed/中高左参差/6.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":6},{"id":"中高左参差-7","name":"通途香","category":"中高左参差","style_description":"左炷香灰直立,其余左弯。","meaning_poem":"通途香号主顺利,犹如大路无荆棘。家里家外好营求,货买货卖皆进益。倘若不是生意人,一切谋望亦可期。","image_path":".protected_data/processed/中高左参差/7.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":7},{"id":"中高左参差-8","name":"走话香","category":"中高左参差","style_description":"右炷香灰直立,其余右弯。","meaning_poem":"走话香号生是非,说话无心走了嘴。本来不关个中事,尴尬啰唣怨得谁。劝尔往后休闲时,莫谈隐私不吃亏。","image_path":".protected_data/processed/中高左参差/8.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":8},{"id":"中高左参差-9","name":"脚生香","category":"中高左参差","style_description":"左炷香灰直立,其余内弯。","meaning_poem":"鲰生香号见小人,\n小人何处言知音。\n百般殷勤非为妙,\n千般体贴怎知仁。\n尔亲非我我非亲,\n日久方知真假人。","image_path":".protected_data/processed/中高左参差/9.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":9},{"id":"中高左参差-10","name":"替身香","category":"中高左参差","style_description":"右炷香灰直立,其余内弯。","meaning_poem":"替身香号主替代,\n孤魂野鬼撞客来。\n家里有人不自在,\n定是幽灵来作怪。\n急急请师驱邪崇,\n不然家门必遭灾。","image_path":".protected_data/processed/中高左参差/10.png","features":{"left_candle":{"height":"低","ash":"内弯"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"平","ash":"直立"}},"index":10},{"id":"中高左参差-11","name":"天器香","category":"中高左参差","style_description":"右炷香灰直立,其余外弯。","meaning_poem":"天器香号恶人现,七日之内上门前。田园房基争界线,因为孩提闹翻脸。无赖帮凶戳是非,侵扰欺凌逞凶焰。","image_path":".protected_data/processed/中高左参差/11.png","features":{"left_candle":{"height":"低","ash":"外弯"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"平","ash":"直立"}},"index":11},{"id":"中高左参差-12","name":"天蓬香","category":"中高左参差","style_description":"左炷香灰直立,其余外弯。","meaning_poem":"天蓬香号须离祖,天使聪明历辛苦。莫向故园种茭黍,可在荒坡栽松竹。待到山林成荫处,掷起珠帘乐自如。","image_path":".protected_data/processed/中高左参差/12.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":12},{"id":"中高左参差-13","name":"受累香","category":"中高左参差","style_description":"中炷香灰直立,其余外弯。","meaning_poem":"受累香号主受屈,城门失火殃池鱼。只为隔壁咫尺间,或因亲情被连及。不出七日定见怪,必定伤财暗憋气。","image_path":".protected_data/processed/中高左参差/13.png","features":{"left_candle":{"height":"低","ash":"外弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"外弯"}},"index":13},{"id":"中高左参差-14","name":"无辜香","category":"中高左参差","style_description":"中炷香灰直立,其余内弯。","meaning_poem":"无辜香号主蒙冤,平白受害或株连。为官平反待何年,香灰作向细判断。倘若亲情有错怪,无须解释和申辩。","image_path":".protected_data/processed/中高左参差/14.png","features":{"left_candle":{"height":"低","ash":"内弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"内弯"}},"index":14},{"id":"中高左参差-15","name":"委身香","category":"中高左参差","style_description":"中炷香灰左弯,其余直立。","meaning_poem":"委身香号傍靠山,违身事人无奈间。纵然从心亦情愿,指望得力夙梦圆。若然还问后来事,依从违背都是怨。","image_path":".protected_data/processed/中高左参差/15.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":15},{"id":"中高左参差-16","name":"委屈香","category":"中高左参差","style_description":"中炷香灰右弯,其余直立。","meaning_poem":"委屈香号心难过,无缘无故受指责。动辄得咎强挑剔,任尔左右都是错。遭人冷眼待遇低,满腹委屈无处说。","image_path":".protected_data/processed/中高左参差/16.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":16},{"id":"中高左参差-17","name":"涉讼香","category":"中高左参差","style_description":"中炷香灰直立,其余左弯。","meaning_poem":"涉讼香号要经官,牵涉诉讼有麻烦。若问吉凶怎结果,香灰作向五行断。生克制化正与反, -一仔细看个端。","image_path":".protected_data/processed/中高左参差/17.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":17},{"id":"中高左参差-18","name":"涉嫌香","category":"中高左参差","style_description":"中炷香灰直立,其余右弯。","meaning_poem":"涉嫌香号犯嫌疑,平白无故遭猜忌。若问能否洗清白,原来神明早示意。香灰黑白定乾坤,香燃七分见玄机。","image_path":".protected_data/processed/中高左参差/18.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":18},{"id":"中高左参差-19","name":"侵扰香","category":"中高左参差","style_description":"左炷香灰左弯,其余右弯。","meaning_poem":"侵扰香号主罗乱,\n国事家事香号断。\n若是国家被侵犯,\n调兵遣将去应战。\n家宅财产人侵犯,\n击鼓衙门有公断。","image_path":".protected_data/processed/中高左参差/19.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":19},{"id":"中高左参差-20","name":"责罚香","category":"中高左参差","style_description":"右炷香灰右弯,其余左弯。","meaning_poem":"责罚香号受责难,\n指责非难受埋怨。\n三日之内须小心,\n闲事闲非莫深贪。\n唯恐错用工夫处,\n被人处罚无言辨。","image_path":".protected_data/processed/中高左参差/20.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":20},{"id":"中高左参差-21","name":"破相香","category":"中高左参差","style_description":"左炷香灰右弯,其余内弯。","meaning_poem":"破相香号容颜毁,\n此劫命元见灾晦。\n情侣仇隙施暴虐,\n修饰美容反不美。\n谁知该当那一类,\n面目皆非半年内。","image_path":".protected_data/processed/中高左参差/21.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":21},{"id":"中高左参差-22","name":"天璋香","category":"中高左参差","style_description":"右炷香灰左弯,其余内弯。","meaning_poem":"天璋香号主吉祥,\n衣食丰足富乐康。\n借问居家何事业,\n不在朝班却经商。\n碧桃花下出灵芝,\n枝头鲜果结成双。","image_path":".protected_data/processed/中高左参差/22.png","features":{"left_candle":{"height":"低","ash":"内弯"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":22},{"id":"中高左参差-23","name":"愚弄香","category":"中高左参差","style_description":"右炷香灰左弯,其余外弯。","meaning_poem":"愚弄香号受蒙蔽,\n被人蒙骗悔不及。\n若然女子被玩弄,\n如若男子被耍戏。\n劝尔世事多慎重,\n三思而行利无弊。","image_path":".protected_data/processed/中高左参差/23.png","features":{"left_candle":{"height":"低","ash":"外弯"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":23},{"id":"中高左参差-24","name":"诱惑香","category":"中高左参差","style_description":"左炷香灰右弯,其余外弯。","meaning_poem":"诱惑香号主欺骗,\n诱拐绣奸骗金钱。\n善知难道心中怨,\n而今当知前车鉴。\n倘若此中无引诱,\n身后虎狼正眈眈。","image_path":".protected_data/processed/中高左参差/24.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":24},{"id":"中高左参差-25","name":"艳情香","category":"中高左参差","style_description":"三炷香灰左弯。","meaning_poem":"艳情香号总关情,痴男怨女谈爱情。借问柳桃共春风,我看分明在黄金。谁知雨骤风狂后,牛郎难会织女星。","image_path":".protected_data/processed/中高左参差/25.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":25},{"id":"中高左参差-26","name":"逸乐香","category":"中高左参差","style_description":"三炷香灰右弯。","meaning_poem":"逸乐香号乐安逸,安逸享乐犹得意。劝尔此香非为妙,逸豫亡身真容易。谁信富贵多疾患,饱食终日未必吉。","image_path":".protected_data/processed/中高左参差/26.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":26},{"id":"中高左参差-27","name":"花魁香","category":"中高左参差","style_description":"左炷香灰直立,其余搭桥。","meaning_poem":"花魁香号说女辈,生来俊俏风流鬼。不是青楼为妓女,定然暗里陪人睡。是也不是看香灰,作向悔吝定淫秽。","image_path":".protected_data/processed/中高左参差/27.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":27},{"id":"中高左参差-28","name":"沮丧香","category":"中高左参差","style_description":"右炷香灰直立,其余搭桥。","meaning_poem":"沮丧香号主心伤,喟然长叹世炎凉。可怜善感重情人,受人歧视遭诽谤。冷漠讥讽人事远,原来度你心性刚。","image_path":".protected_data/processed/中高左参差/28.png","features":{"left_candle":{"height":"低","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"直立"}},"index":28},{"id":"中高左参差-29","name":"厌弃香","category":"中高左参差","style_description":"右炷香灰左弯,其余搭桥。","meaning_poem":"厌弃香号见忧愁,别人嫌弃结情仇。女人私奔承新欢,男人私下养姘头。倘问前缘白首事,天各一方是尽头。","image_path":".protected_data/processed/中高左参差/29.png","features":{"left_candle":{"height":"低","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"左弯"}},"index":29},{"id":"中高左参差-30","name":"姘居香","category":"中高左参差","style_description":"左炷香灰左弯,其余搭桥。","meaning_poem":"姘居香号乱人伦,不是夫妻却厮混。暗锁帘笼入沉迷,儿女前缘荡无存。须知眼下是欢娱,种下孽根自作损。","image_path":".protected_data/processed/中高左参差/30.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":30},{"id":"中高左参差-31","name":"遗弃香","category":"中高左参差","style_description":"右炷香灰右弯,其余搭桥。","meaning_poem":"遗弃香号惨凄凄,\n妻子儿女被抛弃。\n可怜一片善良心,\n谁知虎狼无情义。\n劝尔无须再留恋,\n割断缠绵是如意。","image_path":".protected_data/processed/中高左参差/31.png","features":{"left_candle":{"height":"低","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"右弯"}},"index":31},{"id":"中高左参差-32","name":"索债香","category":"中高左参差","style_description":"左炷香灰右弯,其余搭桥。","meaning_poem":"索债香号总为财,\n旁人欠你要不来。\n若然欠下他人债,\n三日之内来逼债。\n既无内债和外债,\n夫妻相煎情缘债。","image_path":".protected_data/processed/中高左参差/32.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":32},{"id":"中高左参差-33","name":"私通香","category":"中高左参差","style_description":"三炷香灰搭桥。","meaning_poem":"私通香号有奸情,陈仓暗度轻许人。倘然不是儿女事,暗里勾结谋算人。是假是真香灰断,作向生克看五行。","image_path":".protected_data/processed/中高左参差/33.png","features":{"left_candle":{"height":"低","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":33},{"id":"中高左参差-34","name":"遭劫香","category":"中高左参差","style_description":"三炷香灰直立。","meaning_poem":"遭劫香号主不幸,半月之内有灾星。遭遇劫难失钱财,遭受侮辱和蹂躏。倘问灾劫怎得免,急焚香火求神明。","image_path":".protected_data/processed/中高左参差/34.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":34},{"id":"中高右参差-1","name":"忧愤香","category":"中高右参差","style_description":"左炷香灰左弯,其余直立。","meaning_poem":"忧愤香号主愤慨,几番做事有人坏。每次成功都有破,求财不成反累债。借问报应有没有,三五个月自明白。","image_path":".protected_data/processed/中高右参差/1.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"低","ash":"直立"}},"index":1},{"id":"中高右参差-2","name":"威胁香","category":"中高右参差","style_description":"右炷香灰右弯,其余直立。","meaning_poem":"威胁香号主堪忧,有人威胁或利诱。旦看自此半月内,或因钱财或因仇。武力逼迫不发生,诱拐诈骗肯定有。","image_path":".protected_data/processed/中高右参差/2.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"低","ash":"右弯"}},"index":2},{"id":"中高右参差-3","name":"招事香","category":"中高右参差","style_description":"右炷香灰左弯,其余直立。","meaning_poem":"招事香号惹人嫌,近有是非生埋怨。本来无有伤人意,多嘴多舌受干连。倘然不是多嘴人,招风招眼生事端。","image_path":".protected_data/processed/中高右参差/3.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"低","ash":"左弯"}},"index":3},{"id":"中高右参差-4","name":"转嫁香","category":"中高右参差","style_description":"左炷香灰右弯,其余直立。","meaning_poem":"转嫁香号主嫁祸,伤天害理损阴德。不是负担不承受,便是罪名要推托。善知小人在背后,劝尔不可不琢磨。","image_path":".protected_data/processed/中高右参差/4.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"低","ash":"直立"}},"index":4},{"id":"中高右参差-5","name":"天荣香","category":"中高右参差","style_description":"右炷香灰直立,其余左弯。","meaning_poem":"天荣香号主繁荣,家业兴盛乐融融。倘若家中有不顺,那是自己不相容。原来命中早排定,生涯虎口显光荣。","image_path":".protected_data/processed/中高右参差/5.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"低","ash":"直立"}},"index":5},{"id":"中高右参差-6","name":"繁难香","category":"中高右参差","style_description":"左炷香灰直立,其余右弯。","meaning_poem":"繁难香号主犯难,般般件件难周全。如何施恩招怨恨,烧香反而引祸端。要知个中真缘由,孤高守旧少机缘。","image_path":".protected_data/processed/中高右参差/6.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":6},{"id":"中高右参差-7","name":"通途香","category":"中高右参差","style_description":"左炷香灰直立,其余左弯。","meaning_poem":"通途香号主顺利,犹如大路无荆棘。家里家外好营求,货买货卖皆进益。倘若不是生意人,一切谋望亦可期。","image_path":".protected_data/processed/中高右参差/7.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"低","ash":"左弯"}},"index":7},{"id":"中高右参差-8","name":"走话香","category":"中高右参差","style_description":"右炷香灰直立,其余右弯。","meaning_poem":"走话香号生是非,说话无心走了嘴。本来不关个中事,尴尬啰唣怨得谁。劝尔往后休闲时,莫谈隐私不吃亏。","image_path":".protected_data/processed/中高右参差/8.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"低","ash":"直立"}},"index":8},{"id":"中高右参差-9","name":"脚生香","category":"中高右参差","style_description":"左炷香灰直立,其余内弯。","meaning_poem":"鲰生香号见小人,\n小人何处言知音。\n百般殷勤非为妙,\n千般体贴怎知仁。\n尔亲非我我非亲,\n日久方知真假人。","image_path":".protected_data/processed/中高右参差/9.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"低","ash":"内弯"}},"index":9},{"id":"中高右参差-10","name":"替身香","category":"中高右参差","style_description":"右炷香灰直立,其余内弯。","meaning_poem":"替身香号主替代,\n孤魂野鬼撞客来。\n家里有人不自在,\n定是幽灵来作怪。\n急急请师驱邪崇,\n不然家门必遭灾。","image_path":".protected_data/processed/中高右参差/10.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"低","ash":"直立"}},"index":10},{"id":"中高右参差-11","name":"天器香","category":"中高右参差","style_description":"右炷香灰直立,其余外弯。","meaning_poem":"天器香号恶人现,七日之内上门前。田园房基争界线,因为孩提闹翻脸。无赖帮凶戳是非,侵扰欺凌逞凶焰。","image_path":".protected_data/processed/中高右参差/11.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"低","ash":"直立"}},"index":11},{"id":"中高右参差-12","name":"天蓬香","category":"中高右参差","style_description":"左炷香灰直立,其余外弯。","meaning_poem":"天蓬香号须离祖,天使聪明历辛苦。莫向故园种茭黍,可在荒坡栽松竹。待到山林成荫处,掷起珠帘乐自如。","image_path":".protected_data/processed/中高右参差/12.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"低","ash":"外弯"}},"index":12},{"id":"中高右参差-13","name":"受累香","category":"中高右参差","style_description":"中炷香灰直立,其余外弯。","meaning_poem":"受累香号主受屈,城门失火殃池鱼。只为隔壁咫尺间,或因亲情被连及。不出七日定见怪,必定伤财暗憋气。","image_path":".protected_data/processed/中高右参差/13.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"低","ash":"外弯"}},"index":13},{"id":"中高右参差-14","name":"无辜香","category":"中高右参差","style_description":"中炷香灰直立,其余内弯。","meaning_poem":"无辜香号主蒙冤,平白受害或株连。为官平反待何年,香灰作向细判断。倘若亲情有错怪,无须解释和申辩。","image_path":".protected_data/processed/中高右参差/14.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"低","ash":"内弯"}},"index":14},{"id":"中高右参差-15","name":"委身香","category":"中高右参差","style_description":"中炷香灰左弯,其余直立。","meaning_poem":"委身香号傍靠山,违身事人无奈间。纵然从心亦情愿,指望得力夙梦圆。若然还问后来事,依从违背都是怨。","image_path":".protected_data/processed/中高右参差/15.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"低","ash":"直立"}},"index":15},{"id":"中高右参差-16","name":"委屈香","category":"中高右参差","style_description":"中炷香灰右弯,其余直立。","meaning_poem":"委屈香号心难过,无缘无故受指责。动辄得咎强挑剔,任尔左右都是错。遭人冷眼待遇低,满腹委屈无处说。","image_path":".protected_data/processed/中高右参差/16.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"低","ash":"直立"}},"index":16},{"id":"中高右参差-17","name":"涉讼香","category":"中高右参差","style_description":"中炷香灰直立,其余左弯。","meaning_poem":"涉讼香号要经官,牵涉诉讼有麻烦。若问吉凶怎结果,香灰作向五行断。生克制化正与反, -一仔细看个端。","image_path":".protected_data/processed/中高右参差/17.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"低","ash":"左弯"}},"index":17},{"id":"中高右参差-18","name":"涉嫌香","category":"中高右参差","style_description":"中炷香灰直立,其余右弯。","meaning_poem":"涉嫌香号犯嫌疑,平白无故遭猜忌。若问能否洗清白,原来神明早示意。香灰黑白定乾坤,香燃七分见玄机。","image_path":".protected_data/processed/中高右参差/18.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"低","ash":"右弯"}},"index":18},{"id":"中高右参差-19","name":"侵扰香","category":"中高右参差","style_description":"左炷香灰左弯,其余右弯。","meaning_poem":"侵扰香号主罗乱,\n国事家事香号断。\n若是国家被侵犯,\n调兵遣将去应战。\n家宅财产人侵犯,\n击鼓衙门有公断。","image_path":".protected_data/processed/中高右参差/19.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":19},{"id":"中高右参差-20","name":"责罚香","category":"中高右参差","style_description":"右炷香灰右弯,其余左弯。","meaning_poem":"责罚香号受责难,\n指责非难受埋怨。\n三日之内须小心,\n闲事闲非莫深贪。\n唯恐错用工夫处,\n被人处罚无言辨。","image_path":".protected_data/processed/中高右参差/20.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":20},{"id":"中高右参差-21","name":"破相香","category":"中高右参差","style_description":"左炷香灰右弯,其余内弯。","meaning_poem":"破相香号容颜毁,\n此劫命元见灾晦。\n情侣仇隙施暴虐,\n修饰美容反不美。\n谁知该当那一类,\n面目皆非半年内。","image_path":".protected_data/processed/中高右参差/21.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"低","ash":"内弯"}},"index":21},{"id":"中高右参差-22","name":"天璋香","category":"中高右参差","style_description":"右炷香灰左弯,其余内弯。","meaning_poem":"天璋香号主吉祥,\n衣食丰足富乐康。\n借问居家何事业,\n不在朝班却经商。\n碧桃花下出灵芝,\n枝头鲜果结成双。","image_path":".protected_data/processed/中高右参差/22.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"高","ash":"内弯"},"right_candle":{"height":"低","ash":"左弯"}},"index":22},{"id":"中高右参差-23","name":"愚弄香","category":"中高右参差","style_description":"右炷香灰左弯,其余外弯。","meaning_poem":"愚弄香号受蒙蔽,\n被人蒙骗悔不及。\n若然女子被玩弄,\n如若男子被耍戏。\n劝尔世事多慎重,\n三思而行利无弊。","image_path":".protected_data/processed/中高右参差/23.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"低","ash":"左弯"}},"index":23},{"id":"中高右参差-24","name":"诱惑香","category":"中高右参差","style_description":"左炷香灰右弯,其余外弯。","meaning_poem":"诱惑香号主欺骗,\n诱拐绣奸骗金钱。\n善知难道心中怨,\n而今当知前车鉴。\n倘若此中无引诱,\n身后虎狼正眈眈。","image_path":".protected_data/processed/中高右参差/24.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"外弯"},"right_candle":{"height":"低","ash":"外弯"}},"index":24},{"id":"中高右参差-25","name":"艳情香","category":"中高右参差","style_description":"三炷香灰左弯。","meaning_poem":"艳情香号总关情,痴男怨女谈爱情。借问柳桃共春风,我看分明在黄金。谁知雨骤风狂后,牛郎难会织女星。","image_path":".protected_data/processed/中高右参差/25.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"左弯"},"right_candle":{"height":"低","ash":"左弯"}},"index":25},{"id":"中高右参差-26","name":"逸乐香","category":"中高右参差","style_description":"三炷香灰右弯。","meaning_poem":"逸乐香号乐安逸,安逸享乐犹得意。劝尔此香非为妙,逸豫亡身真容易。谁信富贵多疾患,饱食终日未必吉。","image_path":".protected_data/processed/中高右参差/26.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"右弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":26},{"id":"中高右参差-27","name":"花魁香","category":"中高右参差","style_description":"左炷香灰直立,其余搭桥。","meaning_poem":"花魁香号说女辈,生来俊俏风流鬼。不是青楼为妓女,定然暗里陪人睡。是也不是看香灰,作向悔吝定淫秽。","image_path":".protected_data/processed/中高右参差/27.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":27},{"id":"中高右参差-28","name":"沮丧香","category":"中高右参差","style_description":"右炷香灰直立,其余搭桥。","meaning_poem":"沮丧香号主心伤,喟然长叹世炎凉。可怜善感重情人,受人歧视遭诽谤。冷漠讥讽人事远,原来度你心性刚。","image_path":".protected_data/processed/中高右参差/28.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"低","ash":"直立"}},"index":28},{"id":"中高右参差-29","name":"厌弃香","category":"中高右参差","style_description":"右炷香灰左弯,其余搭桥。","meaning_poem":"厌弃香号见忧愁,别人嫌弃结情仇。女人私奔承新欢,男人私下养姘头。倘问前缘白首事,天各一方是尽头。","image_path":".protected_data/processed/中高右参差/29.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"低","ash":"左弯"}},"index":29},{"id":"中高右参差-30","name":"姘居香","category":"中高右参差","style_description":"左炷香灰左弯,其余搭桥。","meaning_poem":"姘居香号乱人伦,不是夫妻却厮混。暗锁帘笼入沉迷,儿女前缘荡无存。须知眼下是欢娱,种下孽根自作损。","image_path":".protected_data/processed/中高右参差/30.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":30},{"id":"中高右参差-31","name":"遗弃香","category":"中高右参差","style_description":"右炷香灰右弯,其余搭桥。","meaning_poem":"遗弃香号惨凄凄,\n妻子儿女被抛弃。\n可怜一片善良心,\n谁知虎狼无情义。\n劝尔无须再留恋,\n割断缠绵是如意。","image_path":".protected_data/processed/中高右参差/31.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"低","ash":"右弯"}},"index":31},{"id":"中高右参差-32","name":"索债香","category":"中高右参差","style_description":"左炷香灰右弯,其余搭桥。","meaning_poem":"索债香号总为财,\n旁人欠你要不来。\n若然欠下他人债,\n三日之内来逼债。\n既无内债和外债,\n夫妻相煎情缘债。","image_path":".protected_data/processed/中高右参差/32.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":32},{"id":"中高右参差-33","name":"私通香","category":"中高右参差","style_description":"三炷香灰搭桥。","meaning_poem":"私通香号有奸情,陈仓暗度轻许人。倘然不是儿女事,暗里勾结谋算人。是假是真香灰断,作向生克看五行。","image_path":".protected_data/processed/中高右参差/33.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"高","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":33},{"id":"中高右参差-34","name":"遭劫香","category":"中高右参差","style_description":"三炷香灰直立。","meaning_poem":"遭劫香号主不幸,半月之内有灾星。遭遇劫难失钱财,遭受侮辱和蹂躏。倘问灾劫怎得免,急焚香火求神明。","image_path":".protected_data/processed/中高右参差/34.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"高","ash":"直立"},"right_candle":{"height":"低","ash":"直立"}},"index":34},{"id":"中低右参差-1","name":"病笃香","category":"中低右参差","style_description":"左炷香灰左弯,其余直立。","meaning_poem":"病笃香号病沉重,不遇良药好郎中。而今人如风里烛,浮云偏使月朦胧。善知命在甘泉竭,可来幽地种青松。","image_path":".protected_data/processed/中低右参差/1.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"低","ash":"直立"}},"index":1},{"id":"中低右参差-2","name":"沉痼香","category":"中低右参差","style_description":"右炷香灰右弯,其余直立。","meaning_poem":"沉痼香号闻呻吟,家中必有久病人。求医问药不见效,累人累心费金银。借问何处有良医,香灰作向自分明。","image_path":".protected_data/processed/中低右参差/2.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"低","ash":"右弯"}},"index":2},{"id":"中低右参差-3","name":"天哀香","category":"中低右参差","style_description":"右炷香灰左弯,其余直立。","meaning_poem":"天哀香号主悲哀,伤心流泪满胸怀。七日之内有丧事,举家哀痛哭伤怀。若问何人先归去,香灰作向细推排。","image_path":".protected_data/processed/中低右参差/3.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"低","ash":"左弯"}},"index":3},{"id":"中低右参差-4","name":"天伤香","category":"中低右参差","style_description":"左炷香灰右弯,其余直立。","meaning_poem":"天伤香号主伤悲,泪洒衣襟哭断魂。不是亲人要离别,定是知己要远行。若问何时重相见,香灰作向看分明。","image_path":".protected_data/processed/中低右参差/4.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"低","ash":"直立"}},"index":4},{"id":"中低右参差-5","name":"天殃香","category":"中低右参差","style_description":"右炷香灰直立,其余左弯。","meaning_poem":"天殃香号主灾殃,横祸飞来不可当。火盗官非兼病患,家门不利有灾殃。若问如何能化解,诚心祈祷保安康。","image_path":".protected_data/processed/中低右参差/5.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"低","ash":"左弯"},"right_candle":{"height":"低","ash":"直立"}},"index":5},{"id":"中低右参差-6","name":"天祸香","category":"中低右参差","style_description":"左炷香灰直立,其余右弯。","meaning_poem":"天祸香号主祸来,口舌是非进门来。小人背后搬弄事,平地风波起祸灾。若问何时能平息,香灰作向避凶灾。","image_path":".protected_data/processed/中低右参差/6.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"右弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":6},{"id":"中低右参差-7","name":"天哭香","category":"中低右参差","style_description":"左炷香灰直立,其余左弯。","meaning_poem":"天哭香号哭声哀,丧车过门把孝戴。不是他人送葬去,定是自家有悲哀。若问何人先逝去,香灰作向细安排。","image_path":".protected_data/processed/中低右参差/7.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"左弯"},"right_candle":{"height":"低","ash":"左弯"}},"index":7},{"id":"中低右参差-8","name":"天泪香","category":"中低右参差","style_description":"右炷香灰直立,其余右弯。","meaning_poem":"天泪香号主悲泣,伤心流泪眼迷离。不是冤家来作对,定是骨肉要分离。若问如何能和解,香灰作向看时机。","image_path":".protected_data/processed/中低右参差/8.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"低","ash":"右弯"},"right_candle":{"height":"低","ash":"直立"}},"index":8},{"id":"中低右参差-9","name":"天愁香","category":"中低右参差","style_description":"左炷香灰直立,其余内弯。","meaning_poem":"天愁香号主忧愁,心事重重锁眉头。进退两难无计处,坐立不安心犯愁。若问何时能解脱,香灰作向自消忧。","image_path":".protected_data/processed/中低右参差/9.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"内弯"},"right_candle":{"height":"低","ash":"内弯"}},"index":9},{"id":"中低右参差-10","name":"天忧香","category":"中低右参差","style_description":"右炷香灰直立,其余内弯。","meaning_poem":"天忧香号主忧虑,百般心事压心底。坐卧不安难入梦,茶饭不思无主意。若问如何能解忧,香灰作向寻妙计。","image_path":".protected_data/processed/中低右参差/10.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"低","ash":"内弯"},"right_candle":{"height":"低","ash":"直立"}},"index":10},{"id":"中低右参差-11","name":"天郁香","category":"中低右参差","style_description":"右炷香灰直立,其余外弯。","meaning_poem":"天郁香号主郁闷,心中不快难舒伸。有话难言藏心底,愁眉不展闷昏昏。若问何时能舒畅,香灰作向解愁云。","image_path":".protected_data/processed/中低右参差/11.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"低","ash":"外弯"},"right_candle":{"height":"低","ash":"直立"}},"index":11},{"id":"中低右参差-12","name":"天闷香","category":"中低右参差","style_description":"左炷香灰直立,其余外弯。","meaning_poem":"天闷香号主烦闷,心情不畅少精神。闭门不出无兴味,独坐窗前暗自忖。若问如何能解闷,香灰作向寻开心。","image_path":".protected_data/processed/中低右参差/12.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"外弯"},"right_candle":{"height":"低","ash":"外弯"}},"index":12},{"id":"中低右参差-13","name":"天结香","category":"中低右参差","style_description":"中炷香灰直立,其余外弯。","meaning_poem":"天结香号主纠结,千头万绪难分拆。心中有事解不开,进退维谷空徘徊。若问如何能解脱,香灰作向免疑猜。","image_path":".protected_data/processed/中低右参差/13.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"低","ash":"外弯"}},"index":13},{"id":"中低右参差-14","name":"天解香","category":"中低右参差","style_description":"中炷香灰直立,其余内弯。","meaning_poem":"天解香号主化解,冤家宜解不宜结。是非恩怨随风散,冰释前嫌重相悦。若问如何能和解,香灰作向看时节。","image_path":".protected_data/processed/中低右参差/14.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"低","ash":"内弯"}},"index":14},{"id":"中低右参差-15","name":"天阻香","category":"中低右参差","style_description":"中炷香灰左弯,其余直立。","meaning_poem":"天阻香号主阻碍,好事多磨费疑猜。前进受阻难如意,半途而废志难谐。若问如何能突破,香灰作向把路开。","image_path":".protected_data/processed/中低右参差/15.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"左弯"},"right_candle":{"height":"低","ash":"直立"}},"index":15},{"id":"中低右参差-16","name":"天碍香","category":"中低右参差","style_description":"中炷香灰右弯,其余直立。","meaning_poem":"天碍香号主障碍,事与愿违多无奈。面前有山难跨越,进退两难心不快。若问如何能克服,香灰作向寻计策。","image_path":".protected_data/processed/中低右参差/16.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"右弯"},"right_candle":{"height":"低","ash":"直立"}},"index":16},{"id":"中低右参差-17","name":"天滞香","category":"中低右参差","style_description":"中炷香灰直立,其余左弯。","meaning_poem":"天滞香号主滞留,事不顺利使人愁。前进不得后退难,停滞不前心忧忧。若问何时能通达,香灰作向把路修。","image_path":".protected_data/processed/中低右参差/17.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"低","ash":"左弯"}},"index":17},{"id":"中低右参差-18","name":"天塞香","category":"中低右参差","style_description":"中炷香灰直立,其余右弯。","meaning_poem":"天塞香号主阻塞,路不通时事难谐。水泄不通成僵局,愁眉不展怨无涯。若问如何能疏通,香灰作向有方法。","image_path":".protected_data/processed/中低右参差/18.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"低","ash":"右弯"}},"index":18},{"id":"中低右参差-19","name":"天隔香","category":"中低右参差","style_description":"左炷香灰左弯,其余右弯。","meaning_poem":"天隔香号主隔离,咫尺天涯难相依。对面相逢不相识,如同陌路各东西。若问何时能相聚,香灰作向看时机。","image_path":".protected_data/processed/中低右参差/19.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"低","ash":"右弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":19},{"id":"中低右参差-20","name":"天远香","category":"中低右参差","style_description":"右炷香灰右弯,其余左弯。","meaning_poem":"天远香号主遥远,相隔万里难相见。音信不通人不见,望穿秋水泪涟涟。若问何时能团圆,香灰作向看机缘。","image_path":".protected_data/processed/中低右参差/20.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"低","ash":"左弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":20},{"id":"中低右参差-21","name":"天离香","category":"中低右参差","style_description":"左炷香灰右弯,其余内弯。","meaning_poem":"天离香号主分离,骨肉分离泪沾衣。不是生离是死别,肝肠寸断痛悲凄。若问何时能相聚,香灰作向自有期。","image_path":".protected_data/processed/中低右参差/21.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"低","ash":"内弯"},"right_candle":{"height":"低","ash":"内弯"}},"index":21},{"id":"中低右参差-22","name":"天合香","category":"中低右参差","style_description":"右炷香灰左弯,其余内弯。","meaning_poem":"天合香号主和合,失散亲人重聚合。破镜重圆成美事,夫妻团圆乐呵呵。若问何时能和合,香灰作向看定夺。","image_path":".protected_data/processed/中低右参差/22.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"低","ash":"内弯"},"right_candle":{"height":"低","ash":"左弯"}},"index":22},{"id":"中低右参差-23","name":"天聚香","category":"中低右参差","style_description":"右炷香灰左弯,其余外弯。","meaning_poem":"天聚香号主团聚,分散家人重相遇。骨肉团圆喜洋洋,共享天伦乐无比。若问何时能相聚,香灰作向有佳期。","image_path":".protected_data/processed/中低右参差/23.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"低","ash":"外弯"},"right_candle":{"height":"低","ash":"左弯"}},"index":23},{"id":"中低右参差-24","name":"天散香","category":"中低右参差","style_description":"左炷香灰右弯,其余外弯。","meaning_poem":"天散香号主离散,家人分散各东西。不是生离是死别,痛心疾首泪悲啼。若问何时能重聚,香灰作向看时机。","image_path":".protected_data/processed/中低右参差/24.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"低","ash":"外弯"},"right_candle":{"height":"低","ash":"外弯"}},"index":24},{"id":"中低右参差-25","name":"天叛香","category":"中低右参差","style_description":"三炷香灰左弯。","meaning_poem":"天叛香号主背叛,朋友反目成仇怨。昔日恩情全忘却,反目成仇不相见。若问如何能挽回,香灰作向看机缘。","image_path":".protected_data/processed/中低右参差/25.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"低","ash":"左弯"},"right_candle":{"height":"低","ash":"左弯"}},"index":25},{"id":"中低右参差-26","name":"天和香","category":"中低右参差","style_description":"三炷香灰右弯。","meaning_poem":"天和香号主和好,冤家对头成知交。化干戈为玉帛,相逢一笑泯恩仇。若问何时能和好,香灰作向自可求。","image_path":".protected_data/processed/中低右参差/26.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"低","ash":"右弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":26},{"id":"中低右参差-27","name":"天祸香","category":"中低右参差","style_description":"左炷香灰直立,其余搭桥。","meaning_poem":"天祸香号大祸临,天灾人祸找上门。不是火灾就是盗,疾病缠身苦呻吟。若问如何能化解,诚心祈祷求神灵。","image_path":".protected_data/processed/中低右参差/27.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":27},{"id":"中低右参差-28","name":"天幸香","category":"中低右参差","style_description":"右炷香灰直立,其余搭桥。","meaning_poem":"天幸香号主侥幸,险中求胜得安宁。死里逃生真侥幸,大难不死有后福。若问今后如何走,香灰作向指迷津。","image_path":".protected_data/processed/中低右参差/28.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"低","ash":"直立"}},"index":28},{"id":"中低右参差-29","name":"天危香","category":"中低右参差","style_description":"左炷香灰左弯,其余搭桥。","meaning_poem":"天危香号主危险,险象环生在眼前。步步小心防不测,稍有不慎命难全。若问如何能脱险,香灰作向避凶难。","image_path":".protected_data/processed/中低右参差/29.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":29},{"id":"中低右参差-30","name":"天安香","category":"中低右参差","style_description":"右炷香灰右弯,其余搭桥。","meaning_poem":"天安香号主平安,险过滩头心放宽。虽然经历风和浪,终得平安回港湾。若问今后如何走,香灰作向保平安。","image_path":".protected_data/processed/中低右参差/30.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"低","ash":"右弯"}},"index":30},{"id":"中低右参差-31","name":"天保香","category":"中低右参差","style_description":"左炷香灰右弯,其余搭桥。","meaning_poem":"天保香号主保佑,神灵保佑免灾忧。千灾万祸化为尘,平安无事度春秋。若问何人来保佑,香灰作向看缘由。","image_path":".protected_data/processed/中低右参差/31.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":31},{"id":"中低右参差-32","name":"天佑香","category":"中低右参差","style_description":"右炷香灰左弯,其余搭桥。","meaning_poem":"天佑香号主庇佑,上天保佑福泽厚。逢凶化吉常自在,遇难呈祥乐无忧。若问如何能长久,香灰作向知根由。","image_path":".protected_data/processed/中低右参差/32.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"低","ash":"左弯"}},"index":32},{"id":"中低右参差-33","name":"天护香","category":"中低右参差","style_description":"三炷香灰搭桥。","meaning_poem":"天护香号主护佑,神明护佑在左右。千难万险都不怕,平安无事度春秋。若问如何能长久,诚心向善可长久。","image_path":".protected_data/processed/中低右参差/33.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":33},{"id":"中低右参差-34","name":"天康香","category":"中低右参差","style_description":"三炷香灰直立。","meaning_poem":"天康香号主健康,身体康泰精神旺。无灾无病少烦恼,福寿绵长乐安康。若问如何能长久,修身养性是良方。","image_path":".protected_data/processed/中低右参差/34.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"低","ash":"直立"}},"index":34},{"id":"中低式-1","name":"月华香","category":"中低式","style_description":"左炷香灰左弯,其余直立。","meaning_poem":"月华香号月光明,\n月光彩环闪粼粼。\n善知运至如天月,\n欢乐团圆水龙吟。\n若问前程婚嫁事。\n月下自是好光荫。","image_path":".protected_data/processed/中低式/1.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":1},{"id":"中低式-2","name":"噩梦香","category":"中低式","style_description":"右炷香灰右弯,其余直立。","meaning_poem":"噩梦香号主虚惊,\n噩梦过后乃安平。\n三日之内须小心,\n当差宿站或旅行。\n车前马后人聚处,\n提防遇险人受惊。","image_path":".protected_data/processed/中低式/2.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":2},{"id":"中低式-3","name":"知音香","category":"中低式","style_description":"右炷香灰左弯,其余直立。","meaning_poem":"知音香号遇相知,\n事事称心如心志。\n匹配姻缘前世事,\n一朵红萼映莲池。\n满塘花开竞芬芳,\n庭前美酒醉吟诗。","image_path":".protected_data/processed/中低式/3.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":3},{"id":"中低式-4","name":"显荣香","category":"中低式","style_description":"左炷香灰右弯,其余直立。","meaning_poem":"显荣香号主显贵,\n男当高官女当妃。\n呼奴唤婢权势大,\n凤阁龙楼映光辉。\n纵然山野一村夫,\n必有名利振家威。","image_path":".protected_data/processed/中低式/4.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":4},{"id":"中低式-5","name":"天晦香","category":"中低式","style_description":"右炷香灰直立,其余左弯。","meaning_poem":"天晦香号晦气重,灾琐临身一重重。问婚问子问前程,进退不利且多凶。善知用意须暂缓,经营更须谨慎中。","image_path":".protected_data/processed/中低式/5.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"低","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":5},{"id":"中低式-6","name":"天枢香","category":"中低式","style_description":"左炷香灰直立,其余右弯。","meaning_poem":"天枢香号主显赫,达官显宦富贵阖。禄重终须掌权印,财多未心就有祸。知机莫向河边立,清廉如何受弹劾。","image_path":".protected_data/processed/中低式/6.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":6},{"id":"中低式-7","name":"天骥香","category":"中低式","style_description":"左炷香灰直立,其余左弯。","meaning_poem":"天骥香号主艰辛,不靠祖基靠自力。寒风鸿雁影沉沉,夜雨梧桐声沥沥。灵霜傲雪久奋身,高楼起处待佳期。","image_path":".protected_data/processed/中低式/7.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":7},{"id":"中低式-8","name":"征召香","category":"中低式","style_description":"右炷香灰直立,其余右弯。","meaning_poem":"征召香号主招聘,生涯何处由此定。授职调用逢机遇,施展本领趁年轻。揭榜应招显才能,应征入伍正适龄。","image_path":".protected_data/processed/中低式/8.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"低","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":8},{"id":"中低式-9","name":"名利香","category":"中低式","style_description":"左炷香灰直立,其余内弯。","meaning_poem":"名利香号名利全,\n生涯处处不费难。\n前程自有人依傍,\n高名隐显在人间。\n休论男婚女嫁事,\n幽情天赋指巫山。","image_path":".protected_data/processed/中低式/9.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":9},{"id":"中低式-10","name":"添丁香","category":"中低式","style_description":"右炷香灰直立,其余内弯。","meaning_poem":"添丁香号进人口,\n生下男儿壮门楼。\n倘若善知年事高,\n必然儿孙花枝秀。\n莫愁他有你没有,\n自古人丁善里求。","image_path":".protected_data/processed/中低式/10.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"低","ash":"内弯"},"right_candle":{"height":"平","ash":"直立"}},"index":10},{"id":"中低式-11","name":"天驿香","category":"中低式","style_description":"右炷香灰直立,其余外弯。","meaning_poem":"天驿香号行驿马,平生注定走天涯。西畔是家东畔立,南园种柳北园发。借问此身何处安,马行驿站既是家。","image_path":".protected_data/processed/中低式/11.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"低","ash":"外弯"},"right_candle":{"height":"平","ash":"直立"}},"index":11},{"id":"中低式-12","name":"天机香","category":"中低式","style_description":"左炷香灰直立,其余外弯。","meaning_poem":"天机香号堪称奇,\n驾眠两岸且相宜。\n生涯似鼎分三足,\n金屋藏娇觅踪迹。\n随风人楚醉春风,\n休将言语泄天机。","image_path":".protected_data/processed/中低式/12.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":12},{"id":"中低式-13","name":"小莲花香","category":"中低式","style_description":"中炷香灰直立,其余外弯。","meaning_poem":"小莲花香带露开,\n三日之内贵人来。\n相约相聚同欢乐。\n好事连台喜开怀。\n结婚生子进喜财,\n萼语花枝春常在。","image_path":".protected_data/processed/中低式/13.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"外弯"}},"index":13},{"id":"中低式-14","name":"团圆香","category":"中低式","style_description":"中炷香灰直立,其余内弯。","meaning_poem":"团圆香号主和合,\n鸳鸯水里荡碧波。\n谁知千里却回归,\n无奈破镜又重合。\n若然不涉姻缘事,\n骨肉团聚合家乐。","image_path":".protected_data/processed/中低式/14.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"内弯"}},"index":14},{"id":"中低式-15","name":"太阳香","category":"中低式","style_description":"中炷香灰左弯,其余直立。","meaning_poem":"太阳香号主祯吉,\n福寿绵长甘如茅。\n初时忧危运未通,\n有如阳光云遮蔽。\n有德自有福德报,\n积善人家何凄其。","image_path":".protected_data/processed/中低式/15.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":15},{"id":"中低式-16","name":"太阴香","category":"中低式","style_description":"中炷香灰右弯,其余直立。","meaning_poem":"太阴香号主禧禄,\n禧禄并臻乐自如。\n光风霁日看今时,\n踌躇满志奔仕途。\n须知人在月光下,\n月晕自当心有谱。","image_path":".protected_data/processed/中低式/16.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":16},{"id":"中低式-17","name":"大莲花香","category":"中低式","style_description":"中炷香灰直立,其余左弯。","meaning_poem":"大莲花香报喜来,七日之内见喜财。如月营求得人助,忽有奇遇事可待。借问此身何处好,紫竹林中坐莲台。","image_path":".protected_data/processed/中低式/17.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":17},{"id":"中低式-18","name":"报喜香","category":"中低式","style_description":"中炷香灰直立,其余右弯。","meaning_poem":"报喜香号主吉庆,风送杨花笛韵清。桃李树上生松子,腰金衣紫有功名。倘若小院真潇索,渔歌晚唱梦中惊。","image_path":".protected_data/processed/中低式/18.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":18},{"id":"中低式-19","name":"天砺香","category":"中低式","style_description":"左炷香灰左弯,其余右弯。","meaning_poem":"天砺香号主淬砺,淬火磨砺出利剑。禄位渐高须有险,资财求处自艰难。莫论成败与艰辛,抱负高明契夙愿。","image_path":".protected_data/processed/中低式/19.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"低","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":19},{"id":"中低式-20","name":"好事香","category":"中低式","style_description":"右炷香灰右弯,其余左弯。","meaning_poem":"好事香号主是非,三日之内沾琐碎。只缘生就喜多事,闲事闲非爱多嘴。李长张短言无意,事到临头方知晦。","image_path":".protected_data/processed/中低式/20.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"低","ash":"左弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":20},{"id":"中低式-21","name":"太学香","category":"中低式","style_description":"左炷香灰右弯,其余内弯。","meaning_poem":"太香学号学有成,\n肄业攻读在京城。\n故园春色堪回首。\n上苑春光铺前程。\n善之不是翰林客。\n亦然才智益平生。","image_path":".protected_data/processed/中低式/21.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"低","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":21},{"id":"中低式-22","name":"增益香","category":"中低式","style_description":"右炷香灰左弯,其余内弯。","meaning_poem":"增益香号主增添,\n家中好事一件件。\n新置家俱和衣冠,\n家居装修换新颜。\n不添什物添人口,\n古筝新唱又续弦。","image_path":".protected_data/processed/中低式/22.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"低","ash":"内弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":22},{"id":"中低式-23","name":"祝福香","category":"中低式","style_description":"右炷香灰左弯,其余外弯。","meaning_poem":"祝福香号乐平安,合家欢乐多美满。枝头桃李竞芬芳,满庭珠紫跃金兰。回首经过泪沾巾,而今一路顺风船。","image_path":".protected_data/processed/中低式/23.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"低","ash":"外弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":23},{"id":"中低式-24","name":"徒劳香","category":"中低式","style_description":"左炷香灰右弯,其余外弯。","meaning_poem":"徒劳香号主无益,劳而无功空费力。纵然艰辛任跋涉,往返徒劳不得济。若还欲问缘何故,筑室道谋怨自己。","image_path":".protected_data/processed/中低式/24.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"低","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":24},{"id":"中低式-25","name":"恶事香","category":"中低式","style_description":"三炷香灰左弯。","meaning_poem":"恶事香号主克害,七日之内恶事来。不是债主强讨债,定是小人来责怪。进退多凶人徘徊,是是非非择不开。","image_path":".protected_data/processed/中低式/25.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"低","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":25},{"id":"中低式-26","name":"富裕香","category":"中低式","style_description":"三炷香灰右弯。","meaning_poem":"富裕香号富有余,人情诗礼事事宜。何须问路知前程,人在高楼听消息。休说由来几奔波,穷则思变富可期。","image_path":".protected_data/processed/中低式/26.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"低","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":26},{"id":"中低式-27","name":"怨府香","category":"中低式","style_description":"左炷香灰直立,其余搭桥。","meaning_poem":"怨府香号招众怒,大家怨恨如鼎沸。怨声载道当自省,盛气凌人谁能服。为官为民当善行,为儿为女种下福。","image_path":".protected_data/processed/中低式/27.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":27},{"id":"中低式-28","name":"藏奸香","category":"中低式","style_description":"右炷香灰直立,其余搭桥。","meaning_poem":"藏奸香号怀恶意,满口应承不出力。劝君交人多留心,阿谀奉承非知己。若然不信试试看,三月之内见底细。","image_path":".protected_data/processed/中低式/28.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"平","ash":"直立"}},"index":28},{"id":"中低式-29","name":"凶煞香","category":"中低式","style_description":"左炷香灰左弯,其余搭桥。","meaning_poem":"凶煞香号凶神到,七日之内见凶兆。得意之时偏尴尬,无意之中却跌跤。男儿当避胭脂远,女儿勿对纨绔笑。","image_path":".protected_data/processed/中低式/29.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":29},{"id":"中低式-30","name":"横事香","category":"中低式","style_description":"右炷香灰右弯,其余搭桥。","meaning_poem":"横事香号主凶灾,\n飞来横祸出意外。\n不是有人要自杀。\n便是有人被谋害。\n横死不出此家门,\n倘若免灾须破财。","image_path":".protected_data/processed/中低式/30.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"平","ash":"右弯"}},"index":30},{"id":"中低式-31","name":"天耗香","category":"中低式","style_description":"左炷香灰右弯.其余搭桥。","meaning_poem":"天耗香号财帛散,家业难为心不安。身后几多荣辱事,年来月去几凄然。倒是相逢知音日,始见振翅上碧天。","image_path":".protected_data/processed/中低式/31.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":31},{"id":"中低式-32","name":"天赦香","category":"中低式","style_description":"右炷香灰左弯,其余搭桥。","meaning_poem":"天赦香号主赦免,减免刑罚早出监。从前错用功夫处,只把惺惺唤作闲。莫讶深陷囫囵中,命里天赦迟早见。","image_path":".protected_data/processed/中低式/32.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"平","ash":"左弯"}},"index":32},{"id":"中低式-33","name":"天门香","category":"中低式","style_description":"三炷香灰搭桥。","meaning_poem":"天门香号主赌注,压宝抽头或聚赌。天门青龙任尔坐,谁见神明管赢输。纵然不为博戏事,闲处无聊不自如。","image_path":".protected_data/processed/中低式/33.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"低","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":33},{"id":"中低式-34","name":"献瑞香","category":"中低式","style_description":"三炷香灰直立。","meaning_poem":"献瑞香号大吉利,天女献玉春正丽。若问桑榆田地间。试看后园子规啼。财多财少财找人,可望平步上云梯。","image_path":".protected_data/processed/中低式/34.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"低","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":34},{"id":"左低式-1","name":"催供香","category":"左低式","style_description":"左炷香灰左弯,其余直立。","meaning_poem":"催供香号莫慌惧,祖师临坛祥云聚。天地禄马显峥嵘,更有鲲鹏抚风去。善知殷勤上大供,祈求还愿皆可依。","image_path":".protected_data/processed/左低式/1.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":1},{"id":"左低式-2","name":"天运香","category":"左低式","style_description":"右炷香灰右弯,其余直立。","meaning_poem":"天运香号时运转,泊恩遇贵非从前。回首历历前日事,几多风雨几多怜。等闲莫怨劳心早,生身缘就苦伴甜。","image_path":".protected_data/processed/左低式/2.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":2},{"id":"左低式-3","name":"伐木香","category":"左低式","style_description":"右炷香灰左弯,其余直立。","meaning_poem":"伐木香号助缘深,伐木遇斧得帮衬。得心应手少费力,事半功倍自足珍。既然革新有人助,何必试问浮与沉。","image_path":".protected_data/processed/左低式/3.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":3},{"id":"左低式-4","name":"穿云香","category":"左低式","style_description":"左炷香灰右弯,其余直立。","meaning_poem":"穿云香号主腾飞,一箭穿云箭飞升。弃文学武上青云,换叶移根始见成。万里江山归到底,老来荣显慰平生。","image_path":".protected_data/processed/左低式/4.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":4},{"id":"左低式-5","name":"望月香","category":"左低式","style_description":"右炷香灰直立,其余左弯。","meaning_poem":"望月香号大有望,云开望月月明亮。假如善知问前程,有志不妨重主张。何嗟四海不相识,棠棣花开忆异乡。","image_path":".protected_data/processed/左低式/5.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":5},{"id":"左低式-6","name":"武曲香","category":"左低式","style_description":"左炷香灰直立,其余右弯。","meaning_poem":"武曲香号闪韶光,武人无益显高强。若然武职在朝廷,常得威权辅国疆。即使平民一武夫,武术武功姓名扬。","image_path":".protected_data/processed/左低式/6.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":6},{"id":"左低式-7","name":"雨春香","category":"左低式","style_description":"左炷香灰直立,其余左弯。","meaning_poem":"雨春香号雨纷纷。春雨纷纷春雨深。孤雁传书话知音,凋花遇雨润甘霖。莫嫌亲眷儿女远,奖指春柳黄芽深。","image_path":".protected_data/processed/左低式/7.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":7},{"id":"左低式-8","name":"优遇香","category":"左低式","style_description":"右炷香灰直立,其余右弯。","meaning_poem":"优遇香号主优待,俸给优厚喜心怀。劝君珍惜眼前福,莫将福禄当应该。知恩图报为人本,积德行善福自来。","image_path":".protected_data/processed/左低式/8.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":8},{"id":"左低式-9","name":"天开香","category":"左低式","style_description":"左炷香灰直立,其余内弯。","meaning_poem":"天开香号主豁达,心胸开阔乐无涯。凡事看得皆透彻,不拘小节走天涯。若问前程如何走,香灰作向指路径。","image_path":".protected_data/processed/左低式/9.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":9},{"id":"左低式-10","name":"天阔香","category":"左低式","style_description":"右炷香灰直立,其余内弯。","meaning_poem":"天阔香号主广阔,眼界开阔见识多。胸怀大志走四方,不被琐事来缠缚。若问前程如何走,香灰作向指路途。","image_path":".protected_data/processed/左低式/10.png","features":{"left_candle":{"height":"低","ash":"内弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"平","ash":"直立"}},"index":10},{"id":"左低式-11","name":"天窄香","category":"左低式","style_description":"右炷香灰直立,其余外弯。","meaning_poem":"天窄香号主狭窄,心胸狭隘难开怀。斤斤计较小事情,睚眦必报惹祸灾。若问如何能开阔,香灰作向寻计策。","image_path":".protected_data/processed/左低式/11.png","features":{"left_candle":{"height":"低","ash":"外弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"平","ash":"直立"}},"index":11},{"id":"左低式-12","name":"天隘香","category":"左低式","style_description":"左炷香灰直立,其余外弯。","meaning_poem":"天隘香号主狭隘,眼光短浅见识窄。坐井观天不知大,固执己见难悔改。若问如何能开阔,香灰作向寻明白。","image_path":".protected_data/processed/左低式/12.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":12},{"id":"左低式-13","name":"天通香","category":"左低式","style_description":"中炷香灰直立,其余外弯。","meaning_poem":"天通香号主通达,事事顺利无阻碍。左右逢源皆如意,心想事成乐开怀。若问前程如何走,香灰作向指路来。","image_path":".protected_data/processed/左低式/13.png","features":{"left_candle":{"height":"低","ash":"外弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"外弯"}},"index":13},{"id":"左低式-14","name":"天达香","category":"左低式","style_description":"中炷香灰直立,其余内弯。","meaning_poem":"天达香号主发达,事业兴旺财源广。声名远播传千里,功成名就显荣光。若问前程如何走,香灰作向指方向。","image_path":".protected_data/processed/左低式/14.png","features":{"left_candle":{"height":"低","ash":"内弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"内弯"}},"index":14},{"id":"左低式-15","name":"天阻香","category":"左低式","style_description":"中炷香灰左弯,其余直立。","meaning_poem":"天阻香号主阻碍,好事多磨费疑猜。前进受阻难如意,半途而废志难谐。若问如何能突破,香灰作向把路开。","image_path":".protected_data/processed/左低式/15.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"平","ash":"直立"}},"index":15},{"id":"左低式-16","name":"天碍香","category":"左低式","style_description":"中炷香灰右弯,其余直立。","meaning_poem":"天碍香号主障碍,事与愿违多无奈。面前有山难跨越,进退两难心不快。若问如何能克服,香灰作向寻计策。","image_path":".protected_data/processed/左低式/16.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"平","ash":"直立"}},"index":16},{"id":"左低式-17","name":"天滞香","category":"左低式","style_description":"中炷香灰直立,其余左弯。","meaning_poem":"天滞香号主滞留,事不顺利使人愁。前进不得后退难,停滞不前心忧忧。若问何时能通达,香灰作向把路修。","image_path":".protected_data/processed/左低式/17.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"左弯"}},"index":17},{"id":"左低式-18","name":"天塞香","category":"左低式","style_description":"中炷香灰直立,其余右弯。","meaning_poem":"天塞香号主阻塞,路不通时事难谐。水泄不通成僵局,愁眉不展怨无涯。若问如何能疏通,香灰作向有方法。","image_path":".protected_data/processed/左低式/18.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"右弯"}},"index":18},{"id":"左低式-19","name":"天隔香","category":"左低式","style_description":"左炷香灰左弯,其余右弯。","meaning_poem":"天隔香号主隔离,咫尺天涯难相依。对面相逢不相识,如同陌路各东西。若问何时能相聚,香灰作向看时机。","image_path":".protected_data/processed/左低式/19.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":19},{"id":"左低式-20","name":"天远香","category":"左低式","style_description":"右炷香灰右弯,其余左弯。","meaning_poem":"天远香号主遥远,相隔万里难相见。音信不通人不见,望穿秋水泪涟涟。若问何时能团圆,香灰作向看机缘。","image_path":".protected_data/processed/左低式/20.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":20},{"id":"左低式-21","name":"天离香","category":"左低式","style_description":"左炷香灰右弯,其余内弯。","meaning_poem":"天离香号主分离,骨肉分离泪沾衣。不是生离是死别,肝肠寸断痛悲凄。若问何时能相聚,香灰作向自有期。","image_path":".protected_data/processed/左低式/21.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":21},{"id":"左低式-22","name":"天合香","category":"左低式","style_description":"右炷香灰左弯,其余内弯。","meaning_poem":"天合香号主和合,失散亲人重聚合。破镜重圆成美事,夫妻团圆乐呵呵。若问何时能和合,香灰作向看定夺。","image_path":".protected_data/processed/左低式/22.png","features":{"left_candle":{"height":"低","ash":"内弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":22},{"id":"左低式-23","name":"天聚香","category":"左低式","style_description":"右炷香灰左弯,其余外弯。","meaning_poem":"天聚香号主团聚,分散家人重相遇。骨肉团圆喜洋洋,共享天伦乐无比。若问何时能相聚,香灰作向有佳期。","image_path":".protected_data/processed/左低式/23.png","features":{"left_candle":{"height":"低","ash":"外弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":23},{"id":"左低式-24","name":"天散香","category":"左低式","style_description":"左炷香灰右弯,其余外弯。","meaning_poem":"天散香号主离散,家人分散各东西。不是生离是死别,痛心疾首泪悲啼。若问何时能重聚,香灰作向看时机。","image_path":".protected_data/processed/左低式/24.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"平","ash":"外弯"}},"index":24},{"id":"左低式-25","name":"天叛香","category":"左低式","style_description":"三炷香灰左弯。","meaning_poem":"天叛香号主背叛,朋友反目成仇怨。昔日恩情全忘却,反目成仇不相见。若问如何能挽回,香灰作向看机缘。","image_path":".protected_data/processed/左低式/25.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"平","ash":"左弯"}},"index":25},{"id":"左低式-26","name":"天和香","category":"左低式","style_description":"三炷香灰右弯。","meaning_poem":"天和香号主和好,冤家对头成知交。化干戈为玉帛,相逢一笑泯恩仇。若问何时能和好,香灰作向自可求。","image_path":".protected_data/processed/左低式/26.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":26},{"id":"左低式-27","name":"俸禄香","category":"左低式","style_description":"左炷香灰直立,其余搭桥。","meaning_poem":"俸禄香号主富贵,黄金斗里仗权威。几多俸给足有余,莫言身荣父子辈。回思家事不如许,不是高官有作为。","image_path":".protected_data/processed/左低式/27.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":27},{"id":"左低式-28","name":"厌世香","category":"左低式","style_description":"右炷香灰右弯,其余搭桥。","meaning_poem":"厌世香号主悲观,厌弃人生举步艰。从来霖雨啼鹃泪,不见子规抱春怨。劝尔悟得怎生我,月缺花残亦悠然。","image_path":".protected_data/processed/左低式/28.png","features":{"left_candle":{"height":"低","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"右弯"}},"index":28},{"id":"左低式-29","name":"思禄香","category":"左低式","style_description":"左炷香灰右弯,其余搭桥。","meaning_poem":"恩禄香号福禄多,渐入佳境天助合。若问儿女前程事,负笈从师跻中国。春暖园林桃李放,天姿玉立如松柏。","image_path":".protected_data/processed/左低式/29.png","features":{"left_candle":{"height":"低","ash":"右弯"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":29},{"id":"左低式-30","name":"创业香","category":"左低式","style_description":"右炷香灰左弯,其余搭桥。","meaning_poem":"创业香号主奔劳,潇洒营生逞英豪。有家生我我非法,家外营家故人好。借问吴越平分事,名利分付应提早。","image_path":".protected_data/processed/左低式/30.png","features":{"left_candle":{"height":"低","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"左弯"}},"index":30},{"id":"左低式-31","name":"补天香","category":"左低式","style_description":"三炷香灰搭桥。","meaning_poem":"补天香号难上难,练石补天是空谈。穷困来时家业败,难以补救为时晚。倘人兴旺且平安,浪里覆舟终须看。","image_path":".protected_data/processed/左低式/31.png","features":{"left_candle":{"height":"低","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"平","ash":"搭桥"}},"index":31},{"id":"左低式-32","name":"霁云香","category":"左低式","style_description":"三炷香灰直立。","meaning_poem":"霁云香号映山红,青云得路日高升。春去秋来事示宁,且宜随缘向前程。前边自有知音客,老生凤子振家声。","image_path":".protected_data/processed/左低式/32.png","features":{"left_candle":{"height":"低","ash":"直立"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"平","ash":"直立"}},"index":32},{"id":"左低式-33","name":"天福香","category":"左低式","style_description":"左炷香灰左弯,其余内弯。","meaning_poem":"天福香号主福临,福星高照喜盈门。吉祥如意常相伴,富贵荣华享不尽。若问前程如何走,香灰作向指福门。","image_path":".protected_data/processed/左低式/33.png","features":{"left_candle":{"height":"低","ash":"左弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"平","ash":"内弯"}},"index":33},{"id":"左低式-34","name":"天寿香","category":"左低式","style_description":"右炷香灰右弯,其余外弯。","meaning_poem":"天寿香号主长寿,福寿绵长乐无忧。身体健康精神旺,儿孙满堂享天伦。若问如何能长久,修身养性是根本。","image_path":".protected_data/processed/左低式/34.png","features":{"left_candle":{"height":"低","ash":"外弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"平","ash":"右弯"}},"index":34},{"id":"右斜切式-1","name":"欢喜香","category":"右斜切式","style_description":"左炷香灰左弯,其余直立。","meaning_poem":"欢喜香号人欢畅,\n快意舒畅不寻常。\n满眼春花笑春风,\n欢合欧鹭藏草塘。\n蟠桃枝枝桂花销,\n玉璋范冕列成行。","image_path":".protected_data/processed/右斜切式/1.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"直立"}},"index":1},{"id":"右斜切式-2","name":"渔猎香","category":"右斜切式","style_description":"右炷香灰右弯,其余直立。","meaning_poem":"渔猎香号主悠闲,\n捕鱼猎兔射飞雁。\n独处山林多少兴。\n提携策钩坐水边。\n早知杀生作孽缘,\n谁说唯尔正清闲。","image_path":".protected_data/processed/右斜切式/2.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"右弯"}},"index":2},{"id":"右斜切式-3","name":"疑忌香","category":"右斜切式","style_description":"右炷香灰左弯。其余直立。","meaning_poem":"疑忌香号主多疑,\n小事不藏好争计。\n亲朋邻里常拌嘴,\n夫妻婆媳常唧唧。\n劝尔莫再恶作剧,\n当知后悔来不及。","image_path":".protected_data/processed/右斜切式/3.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"左弯"}},"index":3},{"id":"右斜切式-4","name":"有利香","category":"右斜切式","style_description":"左炷香灰右弯,其余直立。","meaning_poem":"有利香号喜开怀,\n有成有得有钱财。\n只因几阵东风起,\n吹动神仙驾鹤来。\n到此必荣天禄马,\n移将花影上楼台。","image_path":".protected_data/processed/右斜切式/4.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"直立"}},"index":4},{"id":"右斜切式-5","name":"超拔香","category":"右斜切式","style_description":"右炷香灰直立,其余左弯。","meaning_poem":"超拔香号免疾灾,\n寺庙僧道助缘来。\n休怨从来未从容,\n多病多灾前世债。\n惟有打表念经文。\n助尔忏悔消疾灾。","image_path":".protected_data/processed/右斜切式/5.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"低","ash":"直立"}},"index":5},{"id":"右斜切式-6","name":"有喜香","category":"右斜切式","style_description":"左炷香灰直立,其余右弯。","meaning_poem":"有喜香号主怀孕,\n家中有望得子孙。\n满树花开留一果,\n雨后竹林生嫩笋。\n倘然儿孙已占满,\n而今必定交好运。","image_path":".protected_data/processed/右斜切式/6.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":6},{"id":"右斜切式-7","name":"天蛊香","category":"右斜切式","style_description":"左炷香灰直立,其余左弯。","meaning_poem":"天蛊香号主迷惑,花言巧语被蛊惑。回思弄假却成真,黄金未许对谁说。堪叹世情如纸薄,把个痴心好折磨。","image_path":".protected_data/processed/右斜切式/7.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"低","ash":"左弯"}},"index":7},{"id":"右斜切式-8","name":"有益香","category":"右斜切式","style_description":"右炷香灰直立,其余右弯。","meaning_poem":"有益香号有好处,掘井开池得宝珠。居家遇事有人帮,求身进处有人助。街亭叫卖开店铺,近得利来远得福。","image_path":".protected_data/processed/右斜切式/8.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"低","ash":"直立"}},"index":8},{"id":"右斜切式-9","name":"游乐香","category":"右斜切式","style_description":"左炷香灰直立,其余内弯。","meaning_poem":"游乐香号主欢喜,\n游山玩水尽嬉戏。\n看罢村野风光好,\n又觅名山和古迹。\n万里江山收眼底,\n好向云间借月梯。","image_path":".protected_data/processed/右斜切式/9.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"低","ash":"内弯"}},"index":9},{"id":"右斜切式-10","name":"禅悦香","category":"右斜切式","style_description":"右炷香灰直立,其余内弯。","meaning_poem":"禅悦香号主信受,\n三德六味在心头。\n弘法利世修正果,\n真正归依尽形寿。\n巧把尘劳为佛事,\n禅悦为食法喜有。","image_path":".protected_data/processed/右斜切式/10.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"低","ash":"直立"}},"index":10},{"id":"右斜切式-11","name":"天昌香","category":"右斜切式","style_description":"右炷香灰直立,其余外弯。","meaning_poem":"天昌香号主昌盛,国泰民安五谷丰。门庭光显桑榆茂,持弓逐鹿伟业成。若问儿女亲情事,遂心如意沐春风。","image_path":".protected_data/processed/右斜切式/11.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"低","ash":"直立"}},"index":11},{"id":"右斜切式-12","name":"无奈香","category":"右斜切式","style_description":"左炷香灰直立,其余外弯。","meaning_poem":"无奈香号无招法,无可奈何甘作罢。人家无子成机变,我枉工夫雨打花。唧唧夫妻是冤家,别扭儿女是苦瓜。","image_path":".protected_data/processed/右斜切式/12.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"低","ash":"外弯"}},"index":12},{"id":"右斜切式-13","name":"永乐香","category":"右斜切式","style_description":"中炷香灰直立,其余外弯。","meaning_poem":"永乐香号主太平,\n幸逢盛世多安宁。\n骨肉恩中有亲情,\n鸳侣相知心连心。\n有人若问安身处,\n东西南北自己定。","image_path":".protected_data/processed/右斜切式/13.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"外弯"}},"index":13},{"id":"右斜切式-14","name":"永嘉香","category":"右斜切式","style_description":"中炷香灰直立,其余内弯。","meaning_poem":"永嘉香号主美好,\n耕耘休怨有辛劳。\n下得功夫终获宝,\n喜看如今自逍遥。\n若说洞房终身事,\n推枕拥衾雨潇潇。","image_path":".protected_data/processed/右斜切式/14.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"内弯"}},"index":14},{"id":"右斜切式-15","name":"超脱香","category":"右斜切式","style_description":"中炷香灰左弯,其余直立。","meaning_poem":"超脱香号玄机深,蚌腹藏珠受天恩。休嗟荣辱平生事,几许清名自性真。消磨眷爱随波去,一烛清香谢神明。","image_path":".protected_data/processed/右斜切式/15.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"低","ash":"直立"}},"index":15},{"id":"右斜切式-16","name":"丰登香","category":"右斜切式","style_description":"中炷香灰右弯,其余直立。","meaning_poem":"丰登香号好收成,五谷丰登果木盛。燕语莺啼芝兰伴,茅舍竹篱拂金风。朱紫堂前客欢聚,融融沉醉乐今生。","image_path":".protected_data/processed/右斜切式/16.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"低","ash":"直立"}},"index":16},{"id":"右斜切式-17","name":"天退香","category":"右斜切式","style_description":"中炷香灰直立,其余左弯。","meaning_poem":"天退香号临退身,财帛外流难聚身。求婚问嫁多改口,求人办事更伤神。此间进退多惆怅,半月之后再寻真。","image_path":".protected_data/processed/右斜切式/17.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"左弯"}},"index":17},{"id":"右斜切式-18","name":"兵权香","category":"右斜切式","style_description":"中炷香灰直立,其余右弯。","meaning_poem":"兵权香号主威权,千军万马一挥间。殊权应须谢天苍,谁将紫绶镇西关。既然不是戎马人,三朝人物问青天。","image_path":".protected_data/processed/右斜切式/18.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"右弯"}},"index":18},{"id":"右斜切式-19","name":"雨水香","category":"右斜切式","style_description":"左炷香灰左弯,其余右弯。","meaning_poem":"雨水香号报雨情,\n三日之内雨不停。\n雨水调和庄稼好,\n今年收成肯定行。\n正是人逢及时雨,\n风云雨处好光景。","image_path":".protected_data/processed/右斜切式/19.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":19},{"id":"右斜切式-20","name":"天称香","category":"右斜切式","style_description":"右炷香灰右弯,其余左弯。","meaning_poem":"天称香号防暗算,\n飞蝗入禾禾遭难。\n陌路相逢莫亲近,\n人头聚处莫留连。\n名利成就莫轻狂,\n财来财去莫心贪。","image_path":".protected_data/processed/右斜切式/20.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":20},{"id":"右斜切式-21","name":"丰饶香","category":"右斜切式","style_description":"左炷香灰右弯,其余内弯。","meaning_poem":"丰饶香号既富饶,\n衣食无忧乐逍遥。\n假如不是腰金客,\n也得天佑风光好。\n休疑晦滞自凄凄。\n梅花笑傲雪后骄。","image_path":".protected_data/processed/右斜切式/21.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"低","ash":"内弯"}},"index":21},{"id":"右斜切式-22","name":"大过香","category":"右斜切式","style_description":"右炷香灰左弯,其余内弯。","meaning_poem":"大过香号主过错,\n鬼使神差失误多。\n分明紫燕栖檐下,\n但看一眼不垒窝。\n墙外纷纷结硕果,\n偏我开花不结果。","image_path":".protected_data/processed/右斜切式/22.png","features":{"left_candle":{"height":"平","ash":"内弯"},"middle_candle":{"height":"平","ash":"内弯"},"right_candle":{"height":"低","ash":"左弯"}},"index":22},{"id":"右斜切式-23","name":"浮萍香","category":"右斜切式","style_description":"右炷香灰左弯,其余外弯。","meaning_poem":"浮萍香号主浮荡。\n水上浮萍根不长。\n犹如做事无有根,\n随波逐浪无主张。\n若问生意婚嫁事,\n乱点鸳鸯梦一场。","image_path":".protected_data/processed/右斜切式/23.png","features":{"left_candle":{"height":"平","ash":"外弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"低","ash":"左弯"}},"index":23},{"id":"右斜切式-24","name":"梨园香","category":"右斜切式","style_description":"左炷香灰右弯,其余外弯。","meaning_poem":"梨园香号主戏剧,\n梨园听乐看大戏。\n倘问从前今后事,\n忽忧忽喜伴生计。\n来来往往尽是虚,\n易嗔易喜是夫妻。","image_path":".protected_data/processed/右斜切式/24.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"外弯"},"right_candle":{"height":"低","ash":"外弯"}},"index":24},{"id":"右斜切式-25","name":"成功香","category":"右斜切式","style_description":"三炷香灰左弯。","meaning_poem":"成功香号逞英豪,马到成功声名高。祖计生涯事辛苦,谁知时运把人找。倘若不是富翁佬,终归得意自逍遥。","image_path":".protected_data/processed/右斜切式/25.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"左弯"},"right_candle":{"height":"低","ash":"左弯"}},"index":25},{"id":"右斜切式-26","name":"走马香","category":"右斜切式","style_description":"三炷香灰右弯。","meaning_poem":"走马香号主虚夸,走马长街看灯花。劝尔别把虚夸爱,身外繁华难为家。若问财禄若浮云,问嫁问娶镜里花。","image_path":".protected_data/processed/右斜切式/26.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"右弯"},"right_candle":{"height":"低","ash":"右弯"}},"index":26},{"id":"右斜切式-27","name":"鬼崇香","category":"右斜切式","style_description":"左炷香灰直立,其余搭桥。","meaning_poem":"鬼崇香号闹鬼神,家中有人鬼缠身。若间冤魂何处来,是男是女想作甚。三炷香火看左右,金口香诀说的真。","image_path":".protected_data/processed/右斜切式/27.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":27},{"id":"右斜切式-28","name":"恶曜香","category":"右斜切式","style_description":"右炷香灰直立,其余搭桥。","meaning_poem":"恶曜香号凶煞来,七煞凶星降祸灾。平白无事不自在,伤皮破肉口眼歪。不戒三厌五劳事,伤妻害子躲不开。","image_path":".protected_data/processed/右斜切式/28.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"低","ash":"直立"}},"index":28},{"id":"右斜切式-29","name":"迷途香","category":"右斜切式","style_description":"左炷香灰左弯,其余搭桥。","meaning_poem":"迷途香号主迷惘。如同喝了迷魂汤。遇事颠倒错左右,误识黑白人死巷。劝尔舍下贪嗔痴,回头是岸自畅通。","image_path":".protected_data/processed/右斜切式/29.png","features":{"left_candle":{"height":"平","ash":"左弯"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":29},{"id":"右斜切式-30","name":"离巢香","category":"右斜切式","style_description":"右炷香灰右弯,其余搭桥。","meaning_poem":"离巢番号主离异,燕雀离巢飞东西。不见儿女离家去,定主夫妻要分离。是好是歹怎分说,香灰作向看凶吉。","image_path":".protected_data/processed/右斜切式/30.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"低","ash":"右弯"}},"index":30},{"id":"右斜切式-31","name":"天杀香","category":"右斜切式","style_description":"左炷香灰右弯,其余搭桥。","meaning_poem":"天杀香号主伤害,\n七日之内有凶灾。\n犹如残花又临霜,\n好似喝水盐又来。\n灾病连连躲不过,\n伤心伤财真无奈。","image_path":".protected_data/processed/右斜切式/31.png","features":{"left_candle":{"height":"平","ash":"右弯"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":31},{"id":"右斜切式-32","name":"天伤香","category":"右斜切式","style_description":"右炷香灰左弯,其余搭桥。","meaning_poem":"天伤香号主情殇,\n孤鸳独雁正凄怆。\n分明清风明月下,\n城头更鼓夜不长。\n情窦初开堪可叹,\n乳味真情实可伤。","image_path":".protected_data/processed/右斜切式/32.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"低","ash":"左弯"}},"index":32},{"id":"右斜切式-33","name":"地震香","category":"右斜切式","style_description":"三炷香灰蓓桥。","meaning_poem":"地震香号主凶兆,半月之内灾祸到。山崩地裂屋倒塌,哀鸿遍野动号啕。诚然此地无动静,千里之外传噩耗。","image_path":".protected_data/processed/右斜切式/33.png","features":{"left_candle":{"height":"平","ash":"搭桥"},"middle_candle":{"height":"平","ash":"搭桥"},"right_candle":{"height":"低","ash":"搭桥"}},"index":33},{"id":"右斜切式-34","name":"极乐香","category":"右斜切式","style_description":"三炷香灰直立。","meaning_poem":"极乐香号是同乐,须知富贵是功德。不是祖上积阴功,便是尔搭善因果。善知富贵不能淫,清贫承家亦吟歌。","image_path":".protected_data/processed/右斜切式/34.png","features":{"left_candle":{"height":"平","ash":"直立"},"middle_candle":{"height":"平","ash":"直立"},"right_candle":{"height":"低","ash":"直立"}},"index":34}]
;
